test("service entrypoint contract binds RP00.P02.M00.S01 to Service Logic", () => {
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.subphaseId, "RP00.P02.M00.S01");
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.sourceMicroPhaseId, "RP00.P02.M00");
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.title, "Service entrypoint contract");
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.phaseId, "RP00.P02");
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.phaseTitle, "Service Logic");
  assert.equal(CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.status, "production_ready");
  assert.equal(assertControlPlaneServiceEntrypointContract(), true);
});

test("service entrypoint contract exposes the three canonical entrypoints only", () => {
  assert.deepEqual(CONTROL_PLANE_SERVICE_ENTRYPOINT_IDS, [
    "plan_authoring",
    "ai_implementation_handoff",
    "hermes_validation",
  ]);
  assert.deepEqual(
    CONTROL_PLANE_SERVICE_ENTRYPOINT_CONTRACT.entrypoints.map((entrypoint) => entrypoint.id),
    CONTROL_PLANE_SERVICE_ENTRYPOINT_IDS,
  );
  assert.deepEqual(listControlPlaneServiceEntrypointIds(), CONTROL_PLANE_SERVICE_ENTRYPOINT_IDS);
  assert.equal(listControlPlaneServiceEntrypoints().length, 3);
});

