test("tenant boundary precheck denies mismatched actor, resource, or Matter tenant metadata", () => {
  for (const [label, context, blockedRef] of [
    [
      "actor tenant mismatch",
      { actor_tenant_id: "lfos_other_tenant", resource_tenant_id: "lfos_demo_tenant_layout", matter_tenant_id: "lfos_demo_tenant_layout" },
      "blocked.synthetic.tenant_boundary.actor_tenant_mismatch",
    ],
    [
      "resource tenant mismatch",
      { actor_tenant_id: "lfos_demo_tenant_layout", resource_tenant_id: "lfos_other_tenant", matter_tenant_id: "lfos_demo_tenant_layout" },
      "blocked.synthetic.tenant_boundary.resource_tenant_mismatch",
    ],
    [
      "matter tenant mismatch",
      { actor_tenant_id: "lfos_demo_tenant_layout", resource_tenant_id: "lfos_demo_tenant_layout", matter_tenant_id: "lfos_other_tenant" },
      "blocked.synthetic.tenant_boundary.matter_tenant_mismatch",
    ],
  ]) {
    const result = precheckControlPlaneTenantBoundary(normalizedTenantBoundaryRequest(), context);
    assert.equal(result.tenant_boundary_decision, "deny_blocked_claim_required", label);
    assert.equal(result.precheck_passed, false, label);
    assert.equal(result.blocked_claim_refs.includes(blockedRef), true, label);
    assert.equal(result.service_logic_execution_permitted, false, label);
    assert.equal(assertControlPlaneTenantBoundaryPrecheckResult(result), true, label);
  }
});

