test("AI implementation handoff tenant boundary precheck rejects missing tenant context before allow", () => {
  for (const [label, override] of [
    ["null actor tenant", { actor_tenant_id: null }],
    ["empty actor tenant", { actor_tenant_id: "" }],
    ["blank actor tenant", { actor_tenant_id: " " }],
    ["null resource tenant", { resource_tenant_id: null }],
    ["empty resource tenant", { resource_tenant_id: "" }],
    ["blank resource tenant", { resource_tenant_id: " " }],
  ]) {
    assert.throws(
      () => precheckControlPlaneAIImplementationHandoffTenantBoundary(createAIImplementationHandoffNormalizedRequest(override)),
      /trimmed nonblank string/,
      label,
    );
  }
  for (const [label, field] of [
    ["missing actor tenant", "actor_tenant_id"],
    ["missing resource tenant", "resource_tenant_id"],
  ]) {
    const missingContext = createAIImplementationHandoffNormalizedRequest();
    delete missingContext[field];
    assert.throws(
      () => precheckControlPlaneAIImplementationHandoffTenantBoundary(missingContext),
      /missing/,
      label,
    );
  }
});

