test("AI implementation handoff Matter trace precheck fails closed on unsafe claims and wrong source", () => {
  const tenantBoundaryResult = createAIImplementationHandoffTenantBoundaryResult();
  for (const [label, claims] of [
    ["Matter trace bypass", { bypass_matter_trace: true }],
    ["service execution", { execute_service_logic: true }],
    ["product write", { writes_product_state: true }],
    ["implementation handoff draft", { draft_implementation_handoff: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["unknown truthy claim", { unreviewed_matter_access: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneAIImplementationHandoffMatterTrace(tenantBoundaryResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffMatterTrace(
      { ...tenantBoundaryResult, tenant_boundary_precheck_subphase_id: "RP00.P02.M02.S02" },
    ),
    Error,
    "wrong tenant boundary marker",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffMatterTrace({
      ...tenantBoundaryResult,
      tenant_boundary_decision: "deny_blocked_claim_required",
      precheck_passed: false,
      blocked_claim_refs: ["blocked.synthetic.ai_handoff.tenant_boundary.actor_tenant_mismatch"],
    }),
    Error,
    "carried denied tenant boundary",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffMatterTrace(tenantBoundaryResult, null),
    Error,
    "non-object claims",
  );
});

