test("AI implementation handoff audit hint precheck fails closed on unsafe claims and wrong source", () => {
  const permissionResult = createAIImplementationHandoffPermissionResult();
  for (const [label, claims] of [
    ["skip audit", { skip_audit: true }],
    ["omit audit hint", { omit_audit_hint: true }],
    ["write audit event", { write_audit_event: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["mutate audit ledger", { mutate_audit_ledger: true }],
    ["service execution", { execute_service_logic: true }],
    ["product write", { writes_product_state: true }],
    ["implementation handoff draft", { draft_implementation_handoff: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneAIImplementationHandoffAuditHint(permissionResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffAuditHint(permissionResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden audit claim",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffAuditHint(permissionResult, { unreviewed_audit_override: true }),
    /unknown claim/,
    "unknown truthy audit claim",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffAuditHint({
      ...permissionResult,
      permission_precheck_subphase_id: "RP00.P02.M02.S04",
    }),
    Error,
    "wrong permission marker",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffAuditHint({
      ...permissionResult,
      audit_event_ref: "",
    }),
    Error,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffAuditHint(permissionResult, null),
    Error,
    "non-object claims",
  );
});

