test("AI implementation handoff secondary workflow path allows firm-level metadata and validator rejects drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneAIImplementationHandoffMatterTrace(
    createAIImplementationHandoffTenantBoundaryResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
  );
  const permissionResult = precheckControlPlaneAIImplementationHandoffPermission(firmLevelMatterTrace);
  const auditHintResult = precheckControlPlaneAIImplementationHandoffAuditHint(permissionResult);
  const primaryHappyPathResult = precheckControlPlaneAIImplementationHandoffPrimaryHappyPath(auditHintResult);
  const result = precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath(primaryHappyPathResult);
  assert.equal(assertControlPlaneAIImplementationHandoffSecondaryWorkflowPathResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.secondary_workflow_receipt.object_id, "firm_level_ai_implementation_handoff");
  assert.equal(result.secondary_workflow_path_applied, true);
  for (const [label, override] of [
    ["not applied", { secondary_workflow_path_applied: false }],
    ["wrong marker", { secondary_workflow_path_subphase_id: "RP00.P02.M02.S07" }],
    ["runtime route", { runtime_route_created: true }],
    ["authz evaluator", { authz_evaluator_called: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.secondary"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M02.S08" }],
  ]) {
    assert.throws(
      () => assertControlPlaneAIImplementationHandoffSecondaryWorkflowPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("AI implementation handoff secondary workflow path fails closed on unsafe claims and wrong source", () => {
  const primaryHappyPathResult = createAIImplementationHandoffPrimaryHappyPathResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["implementation handoff draft", { draft_implementation_handoff: true }],
    ["product contract mutation", { mutate_product_contract: true }],
    ["AI rule mutation", { mutate_ai_control_rule: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath(primaryHappyPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath(primaryHappyPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath(primaryHappyPathResult, { unreviewed_secondary_workflow_override: true }),
    /unknown claim/,
    "unknown truthy secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_subphase_id: "RP00.P02.M02.S06",
    }),
    Error,
    "wrong primary happy path marker",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      happy_path_receipt: null,
    }),
    Error,
    "missing primary happy path receipt",
  );
  assert.throws(
    () => precheckControlPlaneAIImplementationHandoffSecondaryWorkflowPath(primaryHappyPathResult, null),
    Error,
    "non-object claims",
  );
});

