function createHermesValidationPrecheckResult() {
  const normalized = normalizeControlPlaneServiceRequest({
    entrypoint_id: "hermes_validation",
    tenant_id: "lfos_demo_tenant_layout",
    actor_id: "user_control_plane_operator",
    idempotency_key: "idem_rp00_p02_m03_s02",
    permission_decision_ref: "perm_decision_allow_synthetic",
    audit_event_ref: "audit.synthetic.hermes_validation.request_normalization",
    matter_id: "matter_demo_001",
    payload: { hermes_gate_ref: "synthetic.hermes_validation.fixture" },
  });
  return precheckControlPlaneTenantBoundary(normalized, {
    actor_tenant_id: "lfos_demo_tenant_layout",
    resource_tenant_id: "lfos_demo_tenant_layout",
    matter_tenant_id: "lfos_demo_tenant_layout",
  });
}

function createNormalizedHermesValidationRequest(overrides = {}) {
  return {
    ...normalizeControlPlaneHermesValidationRequest(createHermesValidationPrecheckResult()),
    ...overrides,
  };
}

function createHermesValidationTenantBoundaryResult(overrides = {}) {
  return {
    ...precheckControlPlaneHermesValidationTenantBoundary(createNormalizedHermesValidationRequest()),
    ...overrides,
  };
}

