test("Hermes validation permission precheck allows firm-level metadata and validator rejects result drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneHermesValidationMatterTrace(createHermesValidationTenantBoundaryResult({
    matter_id: null,
    matter_tenant_id: null,
  }));
  const result = precheckControlPlaneHermesValidationPermission(firmLevelMatterTrace);
  assert.equal(assertControlPlaneHermesValidationPermissionPrecheckResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.permission_scope, "firm_level_control_plane_metadata_permission_ref");
  assert.equal(result.permission_precheck_passed, true);
  assert.equal(result.next_subphase, "RP00.P02.M03.S06");
  for (const [label, override] of [
    ["wrong marker", { permission_precheck_subphase_id: "RP00.P02.M03.S04" }],
    ["runtime permission evaluation", { runtime_permission_evaluation_permitted: true }],
    ["authz evaluator", { authz_evaluator_called: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.permission"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S05" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationPermissionPrecheckResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

