test("Hermes validation permission precheck fails closed on unsafe claims and wrong source", () => {
  const matterTraceResult = createHermesValidationMatterTraceResult();
  for (const [label, claims] of [
    ["permission bypass", { bypass_permission: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["service execution", { execute_service_logic: true }],
    ["product write", { writes_product_state: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes execution", { run_hermes_validation: true }],
    ["Hermes evidence", { create_hermes_evidence: true }],
    ["requirement trace bypass", { bypass_requirement_trace: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["runtime route", { create_runtime_route: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationPermission(matterTraceResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationPermission(matterTraceResult, { unreviewed_permission_override: true }),
    /unknown claim/,
    "unknown truthy permission claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPermission(
      { ...matterTraceResult, matter_trace_precheck_subphase_id: "RP00.P02.M03.S03" },
    ),
    /requires RP00.P02.M03.S04 Matter trace result/,
    "wrong Matter trace marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPermission(
      { ...matterTraceResult, entrypoint_id: "ai_implementation_handoff" },
    ),
    /requires hermes_validation entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPermission({}),
    /requires hermes_validation entrypoint/,
    "non-Matter trace object",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPermission(matterTraceResult, null),
    Error,
    "non-object claims",
  );
});

