test("Hermes validation secondary workflow path allows firm-level metadata and validator rejects drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneHermesValidationMatterTrace(createHermesValidationTenantBoundaryResult({
    matter_id: null,
    matter_tenant_id: null,
  }));
  const permissionResult = precheckControlPlaneHermesValidationPermission(firmLevelMatterTrace);
  const auditHintResult = precheckControlPlaneHermesValidationAuditHint(permissionResult);
  const primaryHappyPathResult = precheckControlPlaneHermesValidationPrimaryHappyPath(auditHintResult);
  const result = precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult);
  assert.equal(assertControlPlaneHermesValidationSecondaryWorkflowPathResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.secondary_workflow_receipt.object_id, "firm_level_hermes_validation");
  assert.equal(result.secondary_workflow_path_applied, true);
  for (const [label, override] of [
    ["wrong marker", { secondary_workflow_path_subphase_id: "RP00.P02.M03.S07" }],
    ["Hermes execution", { hermes_validation_execution_permitted: true }],
    ["Hermes evidence", { hermes_evidence_creation_permitted: true }],
    ["runtime route", { runtime_route_created: true }],
    ["authz evaluator", { authz_evaluator_called: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.secondary"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S08" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationSecondaryWorkflowPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Hermes validation secondary workflow path fails closed on unsafe claims and wrong source", () => {
  const primaryHappyPathResult = createHermesValidationPrimaryHappyPathResult();
  for (const invalidPrimaryHappyPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationSecondaryWorkflowPath(invalidPrimaryHappyPathResult),
      /requires S07 primary happy path result/,
      "missing primary happy path result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes execution", { run_hermes_validation: true }],
    ["Hermes evidence", { create_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["requirement trace bypass", { bypass_requirement_trace: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult, { unreviewed_secondary_workflow_override: true }),
    /unknown claim/,
    "unknown truthy secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_subphase_id: "RP00.P02.M03.S06",
    }),
    /requires RP00.P02.M03.S07 primary happy path result/,
    "wrong primary happy path marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      entrypoint_id: "ai_implementation_handoff",
    }),
    /requires hermes_validation entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied primary happy path",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      happy_path_receipt: null,
    }),
    /requires S07 primary happy path result/,
    "missing primary happy path receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult, null),
    Error,
    "non-object claims",
  );
});

