test("Hermes validation state transition enforcement allows explicit transition and validator rejects drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneHermesValidationMatterTrace(createHermesValidationTenantBoundaryResult({
    matter_id: null,
    matter_tenant_id: null,
  }));
  const permissionResult = precheckControlPlaneHermesValidationPermission(firmLevelMatterTrace);
  const auditHintResult = precheckControlPlaneHermesValidationAuditHint(permissionResult);
  const primaryHappyPathResult = precheckControlPlaneHermesValidationPrimaryHappyPath(auditHintResult);
  const secondaryWorkflowPathResult = precheckControlPlaneHermesValidationSecondaryWorkflowPath(primaryHappyPathResult);
  const result = precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, {
    state_transition_from: "secondary_workflow_path_ready",
    state_transition_to: "state_transition_enforced",
  });
  assert.equal(assertControlPlaneHermesValidationStateTransitionEnforcementResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.state_transition_receipt.object_id, "firm_level_hermes_validation");
  assert.equal(result.state_transition_enforcement_applied, true);
  for (const [label, override] of [
    ["not applied", { state_transition_enforcement_applied: false }],
    ["wrong marker", { state_transition_enforcement_subphase_id: "RP00.P02.M03.S08" }],
    ["wrong transition", { state_transition_to: "idempotency_ready" }],
    ["Hermes execution", { hermes_validation_execution_permitted: true }],
    ["Hermes evidence", { hermes_evidence_creation_permitted: true }],
    ["runtime route", { runtime_route_created: true }],
    ["authz evaluator", { authz_evaluator_called: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.state"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S09" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationStateTransitionEnforcementResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Hermes validation state transition enforcement fails closed on unsafe claims and wrong source", () => {
  const secondaryWorkflowPathResult = createHermesValidationSecondaryWorkflowPathResult();
  for (const invalidSecondaryWorkflowPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationStateTransitionEnforcement(invalidSecondaryWorkflowPathResult),
      /requires S08 secondary workflow path result/,
      "missing secondary workflow path result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes execution", { run_hermes_validation: true }],
    ["Hermes evidence", { create_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["secondary workflow bypass", { bypass_secondary_workflow_path: true }],
    ["state transition bypass", { bypass_state_transition: true }],
    ["requirement trace bypass", { bypass_requirement_trace: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden state transition claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, { unreviewed_state_transition_override: true }),
    /unknown claim/,
    "unknown truthy state transition claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, {
      state_transition_from: "primary_happy_path_ready",
    }),
    /invalid state transition/,
    "invalid state transition from",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, {
      state_transition_to: "idempotency_ready",
    }),
    /invalid state transition/,
    "invalid state transition to",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, {
      state_transition_from: true,
    }),
    /trimmed nonblank string/,
    "non-string transition from",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, {
      state_transition_to: " state_transition_enforced ",
    }),
    /trimmed nonblank string/,
    "untrimmed transition to",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_subphase_id: "RP00.P02.M03.S07",
    }),
    /requires RP00.P02.M03.S08 secondary workflow path result/,
    "wrong secondary workflow marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      entrypoint_id: "ai_implementation_handoff",
    }),
    /requires hermes_validation entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied secondary workflow path",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_receipt: null,
    }),
    /requires S08 secondary workflow path result/,
    "missing secondary workflow receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationStateTransitionEnforcement(secondaryWorkflowPathResult, null),
    Error,
    "non-object claims",
  );
});

