test("Hermes validation persistence boundary allows firm-level metadata and validator rejects drift", () => {
  const firmLevelLockRule = precheckControlPlaneHermesValidationLockAcquisitionRule(
    precheckControlPlaneHermesValidationIdempotencyKeyHandling(
      precheckControlPlaneHermesValidationStateTransitionEnforcement(
        precheckControlPlaneHermesValidationSecondaryWorkflowPath(
          precheckControlPlaneHermesValidationPrimaryHappyPath(
            precheckControlPlaneHermesValidationAuditHint(
              precheckControlPlaneHermesValidationPermission(
                precheckControlPlaneHermesValidationMatterTrace(
                  createHermesValidationTenantBoundaryResult({
                    matter_id: null,
                    matter_tenant_id: null,
                  }),
                ),
              ),
            ),
          ),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneHermesValidationPersistenceBoundary(firmLevelLockRule);
  assert.equal(assertControlPlaneHermesValidationPersistenceBoundaryResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.persistence_receipt.object_id, "firm_level_hermes_validation");
  for (const [label, override] of [
    ["not applied", { persistence_boundary_applied: false }],
    ["wrong marker", { persistence_boundary_subphase_id: "RP00.P02.M03.S11" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product persistence", { product_state_persistence_permitted: true }],
    ["persistence record write", { persistence_record_write_permitted: true }],
    ["Hermes evidence", { hermes_evidence_creation_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.persistence"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S12" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationPersistenceBoundaryResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Hermes validation persistence boundary fails closed on unsafe claims and wrong source", () => {
  const lockRuleResult = createHermesValidationLockAcquisitionRuleResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["object store write", { write_object_store: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes validation execution", { run_hermes_validation: true }],
    ["Hermes evidence creation", { create_hermes_evidence: true }],
    ["persist Hermes evidence", { persist_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission", { evaluate_runtime_permission: true }],
    ["AuthZ evaluator", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["persistence boundary bypass", { bypass_persistence_boundary: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationPersistenceBoundary(lockRuleResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary(lockRuleResult, { write_database: 0 }),
    /write_database/,
    "falsy non-false forbidden persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary(lockRuleResult, { unreviewed_persistence_override: true }),
    /unknown claim/,
    "unknown truthy persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_rule_subphase_id: "RP00.P02.M03.S10",
    }),
    Error,
    "wrong lock marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary({
      ...lockRuleResult,
      entrypoint_id: "ai_implementation_handoff",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary({
      ...lockRuleResult,
      lock_receipt: null,
    }),
    Error,
    "missing lock receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied lock result",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationPersistenceBoundary(lockRuleResult, null),
    Error,
    "non-object claims",
  );
});

