test("Hermes validation error mapping allows firm-level metadata and validator rejects drift", () => {
  const firmLevelPersistence = precheckControlPlaneHermesValidationPersistenceBoundary(
    precheckControlPlaneHermesValidationLockAcquisitionRule(
      precheckControlPlaneHermesValidationIdempotencyKeyHandling(
        precheckControlPlaneHermesValidationStateTransitionEnforcement(
          precheckControlPlaneHermesValidationSecondaryWorkflowPath(
            precheckControlPlaneHermesValidationPrimaryHappyPath(
              precheckControlPlaneHermesValidationAuditHint(
                precheckControlPlaneHermesValidationPermission(
                  precheckControlPlaneHermesValidationMatterTrace(
                    createHermesValidationTenantBoundaryResult({
                      matter_id: null,
                      matter_tenant_id: null,
                    }),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneHermesValidationErrorMapping(firmLevelPersistence);
  assert.equal(assertControlPlaneHermesValidationErrorMappingResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.validation_error_mapping_receipt.object_id, "firm_level_hermes_validation");
  for (const [label, override] of [
    ["not applied", { validation_error_mapping_applied: false }],
    ["wrong marker", { validation_error_mapping_subphase_id: "RP00.P02.M03.S12" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["runtime error mapping", { runtime_error_mapping_permitted: true }],
    ["exception translation", { exception_translation_permitted: true }],
    ["error record write", { error_record_write_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product persistence", { product_state_persistence_permitted: true }],
    ["persistence record write", { persistence_record_write_permitted: true }],
    ["Hermes evidence", { hermes_evidence_creation_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.error_mapping"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S13" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationErrorMappingResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Hermes validation error mapping fails closed on unsafe claims and wrong source", () => {
  const persistenceBoundaryResult = createHermesValidationPersistenceBoundaryResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes validation execution", { run_hermes_validation: true }],
    ["Hermes evidence creation", { create_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["runtime error mapping", { map_runtime_error: true }],
    ["register error mapper", { register_error_mapper: true }],
    ["runtime exception translation", { translate_runtime_exception: true }],
    ["persist error record", { persist_error_record: true }],
    ["write error store", { write_error_store: true }],
    ["error UI", { create_error_ui: true }],
    ["validation error mapping bypass", { bypass_validation_error_mapping: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationErrorMapping(persistenceBoundaryResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping(persistenceBoundaryResult, { map_runtime_error: 0 }),
    /map_runtime_error/,
    "falsy non-false forbidden validation error mapping claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping(persistenceBoundaryResult, { unreviewed_error_mapping_override: true }),
    /unknown claim/,
    "unknown truthy validation error mapping claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping({
      ...persistenceBoundaryResult,
      persistence_boundary_subphase_id: "RP00.P02.M03.S11",
    }),
    Error,
    "wrong persistence marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping({
      ...persistenceBoundaryResult,
      entrypoint_id: "ai_implementation_handoff",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping({
      ...persistenceBoundaryResult,
      persistence_receipt: null,
    }),
    Error,
    "missing persistence receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping({
      ...persistenceBoundaryResult,
      persistence_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied persistence result",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationErrorMapping(persistenceBoundaryResult, null),
    Error,
    "non-object claims",
  );
});

