test("Hermes validation review-required routing fails closed on unsafe claims and wrong source", () => {
  const errorMappingResult = createHermesValidationErrorMappingResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes validation execution", { run_hermes_validation: true }],
    ["Hermes evidence creation", { create_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["error store write", { write_error_store: true }],
    ["invoke Claude review", { invoke_claude_review: true }],
    ["call Claude runtime", { call_claude_runtime: true }],
    ["create Claude review", { create_claude_review: true }],
    ["write review queue", { write_review_queue: true }],
    ["assign reviewer", { assign_reviewer: true }],
    ["notify reviewer", { notify_reviewer: true }],
    ["write human approval", { write_human_approval: true }],
    ["review-required bypass", { bypass_review_required_routing: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationReviewRequiredRouting(errorMappingResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting(errorMappingResult, { invoke_claude_review: 0 }),
    /invoke_claude_review/,
    "falsy non-false forbidden review routing claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting(errorMappingResult, { unreviewed_review_route_override: true }),
    /unknown claim/,
    "unknown truthy review routing claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_subphase_id: "RP00.P02.M03.S12",
    }),
    Error,
    "wrong validation error mapping marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting({
      ...errorMappingResult,
      entrypoint_id: "ai_implementation_handoff",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_receipt: null,
    }),
    Error,
    "missing validation error mapping receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied validation error mapping result",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationReviewRequiredRouting(errorMappingResult, null),
    Error,
    "non-object claims",
  );
});

