test("Hermes validation rollback behavior allows firm-level metadata and validator rejects drift", () => {
  const firmLevelBlockedOutput = precheckControlPlaneHermesValidationBlockedClaimOutput(
    precheckControlPlaneHermesValidationApprovalRequiredRouting(
      precheckControlPlaneHermesValidationReviewRequiredRouting(
        precheckControlPlaneHermesValidationErrorMapping(
          precheckControlPlaneHermesValidationPersistenceBoundary(
            precheckControlPlaneHermesValidationLockAcquisitionRule(
              precheckControlPlaneHermesValidationIdempotencyKeyHandling(
                precheckControlPlaneHermesValidationStateTransitionEnforcement(
                  precheckControlPlaneHermesValidationSecondaryWorkflowPath(
                    precheckControlPlaneHermesValidationPrimaryHappyPath(
                      precheckControlPlaneHermesValidationAuditHint(
                        precheckControlPlaneHermesValidationPermission(
                          precheckControlPlaneHermesValidationMatterTrace(
                            createHermesValidationTenantBoundaryResult({
                              matter_id: null,
                              matter_tenant_id: null,
                            }),
                          ),
                        ),
                      ),
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneHermesValidationRollbackBehavior(firmLevelBlockedOutput);
  assert.equal(assertControlPlaneHermesValidationRollbackBehaviorResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.rollback_behavior_receipt.object_id, "firm_level_hermes_validation");
  for (const [label, override] of [
    ["not applied", { rollback_behavior_applied: false }],
    ["wrong marker", { rollback_behavior_subphase_id: "RP00.P02.M03.S16" }],
    ["bad refs", { rollback_strategy_refs: ["RP00.P02.M03.S17.rollback_strategy.other"] }],
    ["bad entries", { rollback_strategy_entries: [] }],
    ["rollback execution", { rollback_execution_permitted: true }],
    ["retry execution", { retry_execution_permitted: true }],
    ["compensation execution", { compensation_execution_permitted: true }],
    ["operator escalation write", { operator_escalation_write_permitted: true }],
    ["customer notification", { customer_notification_permitted: true }],
    ["incident trace write", { incident_trace_write_permitted: true }],
    ["observability write", { observability_event_write_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["Hermes evidence", { hermes_evidence_creation_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M03.S17" }],
  ]) {
    assert.throws(
      () => assertControlPlaneHermesValidationRollbackBehaviorResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Hermes validation rollback behavior fails closed on unsafe claims and wrong source", () => {
  const blockedClaimOutputResult = createHermesValidationBlockedClaimOutputResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["tenant lifecycle mutation", { mutate_tenant_lifecycle: true }],
    ["Hermes validation execution", { run_hermes_validation: true }],
    ["Hermes evidence creation", { create_hermes_evidence: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["invoke Claude review", { invoke_claude_review: true }],
    ["write review queue", { write_review_queue: true }],
    ["write approval queue", { write_approval_queue: true }],
    ["write human approval record", { write_human_approval_record: true }],
    ["write blocked output", { write_blocked_claim_output: true }],
    ["create blocked record", { create_blocked_claim_record: true }],
    ["notify blocked owner", { notify_blocked_claim_owner: true }],
    ["execute rollback", { execute_rollback: true }],
    ["run rollback", { run_rollback: true }],
    ["write rollback state", { write_rollback_state: true }],
    ["persist rollback plan", { persist_rollback_plan: true }],
    ["enqueue retry", { enqueue_retry: true }],
    ["execute retry", { execute_retry: true }],
    ["run compensation", { run_compensation: true }],
    ["write compensation record", { write_compensation_record: true }],
    ["notify operator", { notify_operator: true }],
    ["notify customer", { notify_customer: true }],
    ["create incident trace", { create_incident_trace: true }],
    ["write incident trace", { write_incident_trace: true }],
    ["append observability event", { append_observability_event: true }],
    ["rollback behavior bypass", { bypass_rollback_behavior: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneHermesValidationRollbackBehavior(blockedClaimOutputResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior(blockedClaimOutputResult, { execute_rollback: 0 }),
    /execute_rollback/,
    "falsy non-false forbidden rollback claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior(blockedClaimOutputResult, { unreviewed_rollback_override: true }),
    /unknown claim/,
    "unknown truthy rollback claim",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_subphase_id: "RP00.P02.M03.S15",
    }),
    Error,
    "wrong blocked-claim output marker",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior({
      ...blockedClaimOutputResult,
      entrypoint_id: "plan_authoring",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_receipt: null,
    }),
    Error,
    "missing blocked-claim output receipt",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_decision: "deny_blocked_claim_output",
    }),
    Error,
    "denied blocked-claim output result",
  );
  assert.throws(
    () => precheckControlPlaneHermesValidationRollbackBehavior(blockedClaimOutputResult, null),
    Error,
    "non-object claims",
  );
});

