function assertHermesValidationDeniedPathCaseThrows(testCase, rollbackBehaviorResult) {
  const expectedReasonByForbiddenClaim = Object.freeze({
    execute_service_logic: "service_execution_claim",
    create_runtime_route: "runtime_route_claim",
    writes_product_state: "product_write_claim",
    write_database: "database_write_claim",
    write_storage: "storage_write_claim",
    mutate_tenant_lifecycle: "tenant_lifecycle_mutation_claim",
    run_hermes_validation: "hermes_execution_or_evidence_claim",
    create_hermes_evidence: "hermes_execution_or_evidence_claim",
    append_audit_ledger: "audit_write_claim",
    write_audit_event: "audit_write_claim",
    execute_rollback: "rollback_execution_claim",
    persist_rollback_plan: "rollback_state_write_claim",
    enqueue_retry: "retry_enqueue_claim",
    execute_retry: "retry_execution_claim",
    write_retry_queue: "retry_queue_write_claim",
    write_retry_attempt: "retry_attempt_write_claim",
    persist_retry_schedule: "retry_schedule_write_claim",
    start_retry_timer: "retry_timer_start_claim",
    dispatch_retry_worker: "retry_worker_dispatch_claim",
    write_retry_backoff_state: "retry_backoff_state_write_claim",
    mutate_retry_dedupe_key: "retry_dedupe_mutation_claim",
    run_compensation: "compensation_execution_claim",
    notify_operator: "operator_notification_claim",
    notify_customer: "customer_notification_claim",
    write_incident_trace: "incident_trace_write_claim",
    append_observability_event: "observability_event_write_claim",
    bypass_retry_behavior: "retry_behavior_bypass_claim",
    use_real_client_data: "real_client_data_claim",
    use_real_matter_data: "real_matter_data_claim",
  });
  const expectedMessageByReason = Object.freeze({
    claims_must_be_object: "Hermes validation retry behavior claims must be an object",
    unknown_truthy_retry_behavior_claim: "Hermes validation retry behavior rejects unknown claim unreviewed_retry_override",
    "rollback_behavior_not_RP00.P02.M03.S17": "Hermes validation retry behavior requires RP00.P02.M03.S17 rollback behavior result",
    non_hermes_validation_entrypoint: "Hermes validation retry behavior requires hermes_validation entrypoint",
    missing_rollback_behavior_receipt: "Hermes validation retry behavior requires S17 rollback behavior result",
    rollback_behavior_denied: "Hermes validation rollback behavior result rollback_behavior_decision mismatch",
  });
  const input = {
    ...rollbackBehaviorResult,
    ...(testCase.override ?? {}),
  };
  const claims = testCase.claimsNull === true
    ? null
    : testCase.claim
      ? { [testCase.claim]: testCase.claimValue }
      : {};
  const expectedMessage = testCase.type === "forbidden_claim"
    ? `Hermes validation retry behavior rejects ${testCase.claim}`
    : expectedMessageByReason[testCase.expectedFailClosedOn];
  if (testCase.type === "forbidden_claim") {
    assert.equal(
      expectedReasonByForbiddenClaim[testCase.claim],
      testCase.expectedFailClosedOn,
      testCase.id,
    );
  }
  assert.equal(typeof expectedMessage, "string", testCase.id);
  assert.throws(
    () => precheckControlPlaneHermesValidationRetryBehavior(input, claims),
    (error) => {
      assert.ok(error instanceof Error, testCase.id);
      assert.equal(error.message, expectedMessage, testCase.id);
      return true;
    },
    testCase.id,
  );
}

