test("Permission And Audit Binding request normalization fails closed on unsafe inputs", () => {
  for (const [label, request] of [
    ["wrong entrypoint", createPermissionAuditBindingRequestInput({ entrypoint_id: "claude_review" })],
    ["wrong source microphase", createPermissionAuditBindingRequestInput({ source_micro_phase_id: "RP00.P02.M04" })],
    ["non production-ready contract", createPermissionAuditBindingRequestInput({ service_entrypoint_contract_status: "draft" })],
    ["non production-ready S14 closeout", createPermissionAuditBindingRequestInput({ claude_review_required_routing_closeout_status: "draft" })],
    ["binding context drift", createPermissionAuditBindingRequestInput({ binding_context_ids: CONTROL_PLANE_PERMISSION_AUDIT_BINDING_CONTEXT_IDS.slice(1) })],
    ["required evidence drift", createPermissionAuditBindingRequestInput({ required_evidence_refs: CONTROL_PLANE_PERMISSION_AUDIT_BINDING_SERVICE_ENTRYPOINT_CONTRACT.requiredEvidenceRefs.slice(1) })],
    ["acceptance gate drift", createPermissionAuditBindingRequestInput({ acceptance_gate_ids: CONTROL_PLANE_PERMISSION_AUDIT_BINDING_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds.slice(1) })],
    ["blank role ref", createPermissionAuditBindingRequestInput({ role_check_ref: "" })],
  ]) {
    assert.throws(() => normalizeControlPlanePermissionAuditBindingRequest(request), Error, label);
  }
  for (const [label, claim] of [
    ["product write", { writes_product_state: true }],
    ["runtime permission", { evaluate_runtime_permission: true }],
    ["authz evaluator", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["audit append", { append_audit_ledger: true }],
    ["audit event", { write_audit_event: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["human approval replacement", { replace_human_approval: true }],
    ["source completion", { complete_source_micro_phase: true }],
    ["unknown claim", { unreviewed_permission_audit_override: true }],
  ]) {
    assert.throws(
      () => normalizeControlPlanePermissionAuditBindingRequest(createPermissionAuditBindingRequestInput(), claim),
      Error,
      label,
    );
  }
  assert.throws(
    () => assertNormalizedControlPlanePermissionAuditBindingRequest(
      createNormalizedPermissionAuditBindingRequest({ permission_engine_execution_permitted: true }),
    ),
    Error,
  );
});

