test("Permission And Audit Binding tenant boundary precheck denies actor resource and Matter tenant mismatches", () => {
  for (const [label, overrides, expectedRef] of [
    [
      "actor tenant mismatch",
      { actor_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.permission_audit_binding.tenant_boundary.actor_tenant_mismatch",
    ],
    [
      "resource tenant mismatch",
      { resource_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.permission_audit_binding.tenant_boundary.resource_tenant_mismatch",
    ],
    [
      "Matter tenant missing",
      { matter_tenant_id: null },
      "blocked.synthetic.permission_audit_binding.tenant_boundary.matter_tenant_missing",
    ],
    [
      "Matter tenant mismatch",
      { matter_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.permission_audit_binding.tenant_boundary.matter_tenant_mismatch",
    ],
  ]) {
    const result = precheckControlPlanePermissionAuditBindingTenantBoundary(createNormalizedPermissionAuditBindingRequest(overrides));
    assert.equal(result.tenant_boundary_decision, "deny_blocked_claim_required", label);
    assert.equal(result.precheck_passed, false, label);
    assert.ok(result.blocked_claim_refs.includes(expectedRef), label);
    assert.equal(result.runtime_permission_evaluation_permitted, false, label);
    assert.equal(result.permission_engine_execution_permitted, false, label);
    assert.equal(result.audit_event_write_permitted, false, label);
    assert.equal(result.service_logic_execution_permitted, false, label);
    const wrongRef = expectedRef.endsWith("actor_tenant_mismatch")
      ? "blocked.synthetic.permission_audit_binding.tenant_boundary.resource_tenant_mismatch"
      : "blocked.synthetic.permission_audit_binding.tenant_boundary.actor_tenant_mismatch";
    assert.throws(
      () => assertControlPlanePermissionAuditBindingTenantBoundaryPrecheckResult({
        ...result,
        blocked_claim_refs: [wrongRef],
      }),
      Error,
      `${label} requires its specific blocked claim ref`,
    );
  }
});

test("Permission And Audit Binding tenant boundary precheck fails closed on unsafe claims and wrong source", () => {
  for (const [label, requestOverride, claimOverride] of [
    ["non-permission-audit entrypoint", { entrypoint_id: "claude_review" }, {}],
    ["wrong normalization marker", { normalization_subphase_id: "RP00.P02.M05.S01" }, {}],
    ["wrong source microphase", { source_micro_phase_id: "RP00.P02.M04" }, {}],
    ["tenant boundary bypass claim", {}, { bypass_tenant_boundary: true }],
    ["cross-tenant allow claim", {}, { allow_cross_tenant: true }],
    ["service execution claim", {}, { execute_service_logic: true }],
    ["product write claim", {}, { writes_product_state: true }],
    ["runtime route claim", {}, { create_runtime_route: true }],
    ["runtime permission claim", {}, { evaluate_runtime_permission: true }],
    ["AuthZ evaluator claim", {}, { call_authz_evaluator: true }],
    ["permission engine claim", {}, { run_permission_engine: true }],
    ["security trimming claim", {}, { apply_security_trimming: true }],
    ["audit ledger claim", {}, { append_audit_ledger: true }],
    ["audit event claim", {}, { write_audit_event: true }],
    ["database write claim", {}, { write_database: true }],
    ["storage write claim", {}, { write_storage: true }],
    ["product persistence claim", {}, { persist_product_state: true }],
    ["entity registry mutation claim", {}, { mutate_entity_registry: true }],
    ["human approval replace claim", {}, { replace_human_approval: true }],
    ["human approval bypass claim", {}, { bypass_human_approval: true }],
    ["Claude review bypass claim", {}, { bypass_claude_review: true }],
    ["source completion claim", {}, { complete_source_micro_phase: true }],
    ["unknown truthy claim", {}, { unexpected_boundary_claim: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingTenantBoundary(
        createNormalizedPermissionAuditBindingRequest(requestOverride),
        claimOverride,
      ),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingTenantBoundary(createNormalizedPermissionAuditBindingRequest(), "bad-claims"),
    Error,
    "non-object claims",
  );
});

