test("Permission And Audit Binding secondary workflow path allows firm-level metadata and validator rejects drift", () => {
  const firmLevelAuditHint = precheckControlPlanePermissionAuditBindingAuditHint(
    createPermissionAuditBindingPermissionResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
  );
  const primaryHappyPathResult = precheckControlPlanePermissionAuditBindingPrimaryHappyPath(firmLevelAuditHint);
  const result = precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(primaryHappyPathResult);
  assert.equal(assertControlPlanePermissionAuditBindingSecondaryWorkflowPathResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.secondary_workflow_receipt.object_id, "firm_level_permission_audit_binding");
  assert.equal(result.secondary_workflow_path_applied, true);
  for (const [label, override] of [
    ["wrong marker", { secondary_workflow_path_subphase_id: "RP00.P02.M05.S07" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["authz call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.permission_audit_binding.secondary_workflow_path"] }],
    ["wrong receipt behavior", {
      secondary_workflow_receipt: {
        ...result.secondary_workflow_receipt,
        primary_happy_path_behavior_ref: "precheckControlPlanePermissionAuditHint",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlanePermissionAuditBindingPrimaryHappyPath" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M05.S08" }],
  ]) {
    assert.throws(
      () => assertControlPlanePermissionAuditBindingSecondaryWorkflowPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Permission And Audit Binding secondary workflow path fails closed on unsafe claims and wrong source", () => {
  const primaryHappyPathResult = createPermissionAuditBindingPrimaryHappyPathResult();
  for (const invalidPrimaryHappyPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(invalidPrimaryHappyPathResult),
      /requires S07 primary happy path result/,
      "missing primary happy path result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["mutate audit ledger", { mutate_audit_ledger: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["product persistence", { persist_product_state: true }],
    ["entity registry mutation", { mutate_entity_registry: true }],
    ["replace human approval", { replace_human_approval: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(primaryHappyPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(primaryHappyPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(
      primaryHappyPathResult,
      { unreviewed_secondary_workflow_override: true },
    ),
    /unknown claim/,
    "unknown truthy secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_subphase_id: "RP00.P02.M05.S06",
    }),
    /requires RP00.P02.M05.S07 primary happy path result/,
    "wrong primary marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      happy_path_receipt: null,
    }),
    /requires S07 primary happy path result/,
    "missing primary receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      audit_event_ref: "",
    }),
    /requires S07 primary happy path result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied primary happy path",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_applied: false,
    }),
    Error,
    "unapplied primary happy path",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(primaryHappyPathResult, null),
    Error,
    "non-object claims",
  );
});

