test("Permission And Audit Binding state transition enforcement allows explicit transition and validator rejects drift", () => {
  const firmLevelSecondaryWorkflow = precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath(
    precheckControlPlanePermissionAuditBindingPrimaryHappyPath(
      precheckControlPlanePermissionAuditBindingAuditHint(
        createPermissionAuditBindingPermissionResult({
          matter_id: null,
          matter_tenant_id: null,
        }),
      ),
    ),
  );
  const result = precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(firmLevelSecondaryWorkflow, {
    state_transition_from: "secondary_workflow_path_ready",
    state_transition_to: "state_transition_enforced",
  });
  assert.equal(assertControlPlanePermissionAuditBindingStateTransitionEnforcementResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.state_transition_receipt.object_id, "firm_level_permission_audit_binding");
  assert.equal(result.state_transition_enforcement_applied, true);
  for (const [label, override] of [
    ["wrong marker", { state_transition_enforcement_subphase_id: "RP00.P02.M05.S08" }],
    ["wrong transition", { state_transition_to: "idempotency_ready" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["authz call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.permission_audit_binding.state_transition"] }],
    ["wrong receipt behavior", {
      state_transition_receipt: {
        ...result.state_transition_receipt,
        secondary_workflow_path_behavior_ref: "precheckControlPlanePermissionAuditBindingPrimaryHappyPath",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlanePermissionAuditBindingSecondaryWorkflowPath" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M05.S09" }],
  ]) {
    assert.throws(
      () => assertControlPlanePermissionAuditBindingStateTransitionEnforcementResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Permission And Audit Binding state transition enforcement fails closed on unsafe claims and wrong source", () => {
  const secondaryWorkflowPathResult = createPermissionAuditBindingSecondaryWorkflowPathResult();
  for (const invalidSecondaryWorkflowPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(invalidSecondaryWorkflowPathResult),
      /requires S08 secondary workflow path result/,
      "missing secondary workflow path result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["mutate audit ledger", { mutate_audit_ledger: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["product persistence", { persist_product_state: true }],
    ["entity registry mutation", { mutate_entity_registry: true }],
    ["replace human approval", { replace_human_approval: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["secondary workflow bypass", { bypass_secondary_workflow_path: true }],
    ["state transition bypass", { bypass_state_transition: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(secondaryWorkflowPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(secondaryWorkflowPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden state transition claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(
      secondaryWorkflowPathResult,
      { unreviewed_state_transition_override: true },
    ),
    /unknown claim/,
    "unknown truthy state transition claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(
      secondaryWorkflowPathResult,
      { state_transition_to: "unsafe_transition" },
    ),
    /invalid state transition/,
    "invalid state transition",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_subphase_id: "RP00.P02.M05.S07",
    }),
    /requires RP00.P02.M05.S08 secondary workflow path result/,
    "wrong secondary marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_receipt: null,
    }),
    /requires S08 secondary workflow path result/,
    "missing secondary receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      audit_event_ref: "",
    }),
    /requires S08 secondary workflow path result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied secondary workflow path",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_applied: false,
    }),
    Error,
    "unapplied secondary workflow path",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingStateTransitionEnforcement(secondaryWorkflowPathResult, null),
    Error,
    "non-object claims",
  );
});

