test("Permission And Audit Binding idempotency key handling fails closed on unsafe claims and wrong source", () => {
  const stateTransitionResult = createPermissionAuditBindingStateTransitionEnforcementResult();
  for (const invalidStateTransitionResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling(invalidStateTransitionResult),
      /requires S09 state transition enforcement result/,
      "missing state transition result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["product persistence", { persist_product_state: true }],
    ["idempotency record persistence", { persist_idempotency_record: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock acquisition", { acquire_lock: true }],
    ["state transition bypass", { bypass_state_transition: true }],
    ["idempotency bypass", { bypass_idempotency_key: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling(stateTransitionResult, claims),
      Error,
      label,
    );
  }
  for (const [label, key] of [
    ["non synthetic", "idem.runtime.permission_audit_binding"],
    ["uppercase", "idem.synthetic.PermissionAuditBinding"],
    ["trimmed", " idem.synthetic.permission_audit_binding"],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling(stateTransitionResult, { idempotency_key: key }),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling(stateTransitionResult, { unexpected_idempotency_claim: true }),
    /unknown claim/,
    "unknown truthy idempotency claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_enforcement_subphase_id: "RP00.P02.M05.S08",
    }),
    /requires RP00.P02.M05.S09 state transition enforcement result/,
    "wrong state transition marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_receipt: null,
    }),
    /requires S09 state transition enforcement result/,
    "missing state transition receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      audit_event_ref: "",
    }),
    /requires S09 state transition enforcement result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied state transition",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_enforcement_applied: false,
    }),
    Error,
    "unapplied state transition",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingIdempotencyKeyHandling(stateTransitionResult, null),
    Error,
    "non-object claims",
  );
});

