test("Permission And Audit Binding persistence boundary fails closed on unsafe claims and wrong source", () => {
  const lockRuleResult = createPermissionAuditBindingLockAcquisitionRuleResult();
  for (const invalidLockRuleResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingPersistenceBoundary(invalidLockRuleResult),
      /requires S11 lock acquisition rule result/,
      "missing lock rule result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["product persistence", { persist_product_state: true }],
    ["control-plane persistence", { persist_control_plane_state: true }],
    ["runtime persistence", { persist_runtime_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["object store write", { write_object_store: true }],
    ["file store write", { write_file_store: true }],
    ["cache write", { write_cache: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["persist audit event", { persist_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["idempotency record persistence", { persist_idempotency_record: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock acquisition", { acquire_lock: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["lock record persistence", { persist_lock_record: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence record persistence", { persist_persistence_record: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["UI creation", { create_ui: true }],
    ["persistence boundary bypass", { bypass_persistence_boundary: true }],
    ["lock acquisition rule bypass", { bypass_lock_acquisition_rule: true }],
    ["idempotency bypass", { bypass_idempotency_key: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingPersistenceBoundary(lockRuleResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary(lockRuleResult, { write_database: 0 }),
    /write_database/,
    "falsy non-false forbidden persistence claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary(lockRuleResult, { unexpected_persistence_claim: true }),
    /unknown claim/,
    "unknown truthy persistence claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_rule_subphase_id: "RP00.P02.M05.S10",
    }),
    /requires RP00.P02.M05.S11 lock acquisition rule result/,
    "wrong lock rule marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      lock_receipt: null,
    }),
    /requires S11 lock acquisition rule result/,
    "missing lock receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      audit_event_ref: "",
    }),
    /requires S11 lock acquisition rule result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied lock acquisition result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_rule_applied: false,
    }),
    Error,
    "unapplied lock acquisition result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingPersistenceBoundary(lockRuleResult, null),
    Error,
    "non-object claims",
  );
});

