test("Permission And Audit Binding validation error mapping fails closed on unsafe claims and wrong source", () => {
  const persistenceBoundaryResult = createPermissionAuditBindingPersistenceBoundaryResult();
  for (const invalidPersistenceBoundaryResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingErrorMapping(invalidPersistenceBoundaryResult),
      /requires S12 persistence boundary result/,
      "missing persistence boundary result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["product persistence", { persist_product_state: true }],
    ["control-plane persistence", { persist_control_plane_state: true }],
    ["runtime persistence", { persist_runtime_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["object store write", { write_object_store: true }],
    ["file store write", { write_file_store: true }],
    ["cache write", { write_cache: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["persist audit event", { persist_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["idempotency record persistence", { persist_idempotency_record: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock acquisition", { acquire_lock: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["lock record persistence", { persist_lock_record: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence record persistence", { persist_persistence_record: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["runtime error mapping", { map_runtime_error: true }],
    ["error mapper registration", { register_error_mapper: true }],
    ["exception translation", { translate_runtime_exception: true }],
    ["product exception translation", { translate_product_exception: true }],
    ["runtime error emit", { emit_runtime_error: true }],
    ["error record persistence", { persist_error_record: true }],
    ["error store write", { write_error_store: true }],
    ["error UI", { create_error_ui: true }],
    ["UI creation", { create_ui: true }],
    ["validation error mapping bypass", { bypass_validation_error_mapping: true }],
    ["persistence boundary bypass", { bypass_persistence_boundary: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingErrorMapping(persistenceBoundaryResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping(persistenceBoundaryResult, { map_runtime_error: 0 }),
    /map_runtime_error/,
    "falsy non-false forbidden error mapping claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping(persistenceBoundaryResult, { unexpected_error_mapping_claim: true }),
    /unknown claim/,
    "unknown truthy error mapping claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      persistence_boundary_subphase_id: "RP00.P02.M05.S11",
    }),
    /requires RP00.P02.M05.S12 persistence boundary result/,
    "wrong persistence boundary marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      persistence_receipt: null,
    }),
    /requires S12 persistence boundary result/,
    "missing persistence receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      audit_event_ref: "",
    }),
    /requires S12 persistence boundary result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      persistence_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied persistence boundary result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping({
      ...persistenceBoundaryResult,
      persistence_boundary_applied: false,
    }),
    Error,
    "unapplied persistence boundary result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingErrorMapping(persistenceBoundaryResult, null),
    Error,
    "non-object claims",
  );
});

