test("Permission And Audit Binding review-required routing fails closed on unsafe claims and wrong source", () => {
  const errorMappingResult = createPermissionAuditBindingErrorMappingResult();
  for (const invalidErrorMappingResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting(invalidErrorMappingResult),
      /requires S13 validation error mapping result/,
      "missing validation error mapping result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["product persistence", { persist_product_state: true }],
    ["control-plane persistence", { persist_control_plane_state: true }],
    ["runtime persistence", { persist_runtime_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["Claude runtime review", { invoke_claude_runtime_review: true }],
    ["Claude review", { invoke_claude_review: true }],
    ["Claude runtime call", { call_claude_runtime: true }],
    ["review queue write", { write_review_queue: true }],
    ["review assignment write", { write_review_assignment: true }],
    ["review notification write", { write_review_notification: true }],
    ["assign reviewer", { assign_reviewer: true }],
    ["notify reviewer", { notify_reviewer: true }],
    ["human approval record", { write_human_approval_record: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["runtime error mapping", { map_runtime_error: true }],
    ["exception translation", { translate_runtime_exception: true }],
    ["error store write", { write_error_store: true }],
    ["UI creation", { create_ui: true }],
    ["review-required bypass", { bypass_review_required_routing: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting(errorMappingResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting(errorMappingResult, { invoke_claude_review: 0 }),
    /invoke_claude_review/,
    "falsy non-false forbidden review-required claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting(errorMappingResult, { unexpected_review_required_claim: true }),
    /unknown claim/,
    "unknown truthy review-required claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_subphase_id: "RP00.P02.M05.S12",
    }),
    /requires RP00.P02.M05.S13 validation error mapping result/,
    "wrong validation error mapping marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      entrypoint_id: "claude_review",
    }),
    /requires permission_audit_binding entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_receipt: null,
    }),
    /requires S13 validation error mapping result/,
    "missing validation error mapping receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      audit_event_ref: "",
    }),
    /requires S13 validation error mapping result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied validation error mapping result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting({
      ...errorMappingResult,
      validation_error_mapping_applied: false,
    }),
    Error,
    "unapplied validation error mapping result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingReviewRequiredRouting(errorMappingResult, null),
    Error,
    "non-object claims",
  );
});

