function createPermissionAuditBindingApprovalRequiredRoutingResult(overrides = {}, approvalRoutingClaims = {}) {
  const result = precheckControlPlanePermissionAuditBindingApprovalRequiredRouting(
    createPermissionAuditBindingReviewRequiredRoutingResult(),
    approvalRoutingClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

