function createPermissionAuditBindingBlockedClaimOutputResult(overrides = {}, blockedClaimOutputClaims = {}) {
  const result = precheckControlPlanePermissionAuditBindingBlockedClaimOutput(
    createPermissionAuditBindingApprovalRequiredRoutingResult(),
    blockedClaimOutputClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

