test("Permission And Audit Binding rollback behavior fails closed on unsafe claims and wrong source", () => {
  const blockedClaimOutputResult = createPermissionAuditBindingBlockedClaimOutputResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["audit event write", { write_audit_event: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["review queue", { write_review_queue: true }],
    ["write approval queue", { write_approval_queue: true }],
    ["write blocked output", { write_blocked_claim_output: true }],
    ["execute rollback", { execute_rollback: true }],
    ["rollback state", { write_rollback_state: true }],
    ["enqueue retry", { enqueue_retry: true }],
    ["execute retry", { execute_retry: true }],
    ["compensation", { run_compensation: true }],
    ["operator notification", { notify_operator: true }],
    ["customer notification", { notify_customer: true }],
    ["incident trace", { write_incident_trace: true }],
    ["observability", { append_observability_event: true }],
    ["rollback bypass", { bypass_rollback_behavior: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingRollbackBehavior(blockedClaimOutputResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior(blockedClaimOutputResult, { unexpected_rollback_override: true }),
    /unknown claim/,
    "unknown truthy rollback behavior claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_subphase_id: "RP00.P02.M05.S15",
    }),
    Error,
    "wrong blocked-claim output marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior({
      ...blockedClaimOutputResult,
      entrypoint_id: "hermes_validation",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_receipt: null,
    }),
    Error,
    "missing blocked output receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_decision: "deny_rollback_behavior",
    }),
    Error,
    "denied blocked-claim output result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRollbackBehavior(blockedClaimOutputResult, null),
    Error,
    "non-object claims",
  );
});

