test("Permission And Audit Binding retry behavior fails closed on unsafe claims and wrong source", () => {
  const rollbackBehaviorResult = createPermissionAuditBindingRollbackBehaviorResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["audit event write", { write_audit_event: true }],
    ["permission engine", { run_permission_engine: true }],
    ["review queue", { write_review_queue: true }],
    ["approval queue", { write_approval_queue: true }],
    ["execute rollback", { execute_rollback: true }],
    ["enqueue retry", { enqueue_retry: true }],
    ["execute retry", { execute_retry: true }],
    ["write retry queue", { write_retry_queue: true }],
    ["write retry attempt", { write_retry_attempt: true }],
    ["increment retry attempt", { increment_retry_attempt: true }],
    ["persist retry schedule", { persist_retry_schedule: true }],
    ["start retry timer", { start_retry_timer: true }],
    ["dispatch retry worker", { dispatch_retry_worker: true }],
    ["write retry backoff state", { write_retry_backoff_state: true }],
    ["mutate retry dedupe key", { mutate_retry_dedupe_key: true }],
    ["compensation", { run_compensation: true }],
    ["operator notification", { notify_operator: true }],
    ["customer notification", { notify_customer: true }],
    ["incident trace", { write_incident_trace: true }],
    ["observability", { append_observability_event: true }],
    ["retry behavior bypass", { bypass_retry_behavior: true }],
    ["real matter data", { use_real_matter_data: true }],
  ]) {
    assert.throws(
      () => precheckControlPlanePermissionAuditBindingRetryBehavior(rollbackBehaviorResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior(rollbackBehaviorResult, { unreviewed_retry_override: true }),
    /unknown claim/,
    "unknown truthy retry behavior claim",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior({
      ...rollbackBehaviorResult,
      rollback_behavior_subphase_id: "RP00.P02.M05.S16",
    }),
    Error,
    "wrong rollback behavior marker",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior({
      ...rollbackBehaviorResult,
      entrypoint_id: "claude_review",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior({
      ...rollbackBehaviorResult,
      rollback_behavior_receipt: null,
    }),
    Error,
    "missing rollback behavior receipt",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior({
      ...rollbackBehaviorResult,
      rollback_behavior_decision: "deny_retry_behavior",
    }),
    Error,
    "denied rollback behavior result",
  );
  assert.throws(
    () => precheckControlPlanePermissionAuditBindingRetryBehavior(rollbackBehaviorResult, null),
    Error,
    "non-object claims",
  );
});

