test("Synthetic Fixture Set request normalization fails closed on unsafe inputs", () => {
  for (const [label, request] of [
    ["wrong entrypoint", createSyntheticFixtureSetRequestInput({ entrypoint_id: "permission_audit_binding" })],
    ["wrong source microphase", createSyntheticFixtureSetRequestInput({ source_micro_phase_id: "RP00.P02.M05" })],
    ["non production-ready contract", createSyntheticFixtureSetRequestInput({ service_entrypoint_contract_status: "draft" })],
    ["non production-ready S20 closeout", createSyntheticFixtureSetRequestInput({ permission_audit_binding_closeout_status: "draft" })],
    ["wrong S20 closeout ref", createSyntheticFixtureSetRequestInput({ permission_audit_binding_closeout_ref: "RP00.P02.M05.S19" })],
    ["wrong synthetic policy", createSyntheticFixtureSetRequestInput({ synthetic_only_policy_ref: "RP00.P00.M05.S01" })],
    ["fixture context drift", createSyntheticFixtureSetRequestInput({ fixture_context_ids: CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_SERVICE_CONTEXT_IDS.slice(1) })],
    ["required evidence drift", createSyntheticFixtureSetRequestInput({ required_evidence_refs: CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_SERVICE_ENTRYPOINT_CONTRACT.requiredEvidenceRefs.slice(1) })],
    ["schema drift", createSyntheticFixtureSetRequestInput({ schema_expectation_fields: CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_SERVICE_ENTRYPOINT_CONTRACT.schemaExpectationFields.slice(1) })],
    ["marker drift", createSyntheticFixtureSetRequestInput({ required_fixture_markers: CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_SERVICE_ENTRYPOINT_CONTRACT.requiredFixtureMarkers.slice(1) })],
    ["domain drift", createSyntheticFixtureSetRequestInput({ allowed_domains: ["example.com"] })],
    ["blank fixture ref", createSyntheticFixtureSetRequestInput({ fixture_file_ref: "" })],
  ]) {
    assert.throws(() => normalizeControlPlaneSyntheticFixtureSetRequest(request), Error, label);
  }
  for (const [label, claim] of [
    ["fixture generation", { generate_fixture: true }],
    ["fixture persistence", { persist_fixture: true }],
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["real client data", { use_real_client_data: true }],
    ["secret use", { use_credentials_or_secrets: true }],
    ["source completion", { complete_source_micro_phase: true }],
    ["unknown claim", { unreviewed_fixture_override: true }],
  ]) {
    assert.throws(
      () => normalizeControlPlaneSyntheticFixtureSetRequest(createSyntheticFixtureSetRequestInput(), claim),
      Error,
      label,
    );
  }
  assert.throws(
    () => assertNormalizedControlPlaneSyntheticFixtureSetRequest(
      createNormalizedSyntheticFixtureSetRequest({ fixture_generation_permitted: true }),
    ),
    Error,
  );
});

