test("Synthetic Fixture Set Audit hint precheck allows firm-level metadata and validator rejects drift", () => {
  const permissionResult = createSyntheticFixtureSetPermissionResult({ matter_id: null });
  const result = precheckControlPlaneSyntheticFixtureSetAuditHint(permissionResult);
  assert.equal(result.matter_id, null);
  assert.equal(result.audit_hint.matter_id, null);
  assert.equal(result.audit_hint.object_id, result.fixture_set_id);
  assert.equal(assertControlPlaneSyntheticFixtureSetAuditHintPrecheckResult(result), true);
  assert.throws(
    () => assertControlPlaneSyntheticFixtureSetAuditHintPrecheckResult({
      ...result,
      audit_hint_scope: "runtime_audit_write",
    }),
    Error,
    "audit hint scope drift",
  );
  assert.throws(
    () => assertControlPlaneSyntheticFixtureSetAuditHintPrecheckResult({
      ...result,
      audit_event_write_permitted: true,
    }),
    Error,
    "audit event write drift",
  );
});

