test("Synthetic Fixture Set Primary happy path allows firm-level metadata and validator rejects drift", () => {
  const auditHintResult = precheckControlPlaneSyntheticFixtureSetAuditHint(
    createSyntheticFixtureSetPermissionResult({ matter_id: null }),
  );
  const result = precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(auditHintResult);
  assert.equal(result.matter_id, null);
  assert.equal(result.happy_path_receipt.matter_id, null);
  assert.equal(result.happy_path_receipt.object_id, result.fixture_set_id);
  assert.equal(assertControlPlaneSyntheticFixtureSetPrimaryHappyPathResult(result), true);
  assert.throws(
    () => assertControlPlaneSyntheticFixtureSetPrimaryHappyPathResult({
      ...result,
      happy_path_scope: "runtime_fixture_generation",
    }),
    Error,
    "happy path scope drift",
  );
  assert.throws(
    () => assertControlPlaneSyntheticFixtureSetPrimaryHappyPathResult({
      ...result,
      fixture_generation_permitted: true,
    }),
    Error,
    "fixture generation drift",
  );
});

test("Synthetic Fixture Set Primary happy path fails closed on unsafe claims and wrong source", () => {
  const baseAuditHintResult = createSyntheticFixtureSetAuditHintResult();
  for (const [label, resultOverride, claimOverride] of [
    ["non-synthetic entrypoint", { entrypoint_id: "permission_audit_binding" }, {}],
    ["wrong audit hint marker", { audit_hint_precheck_subphase_id: "RP00.P02.M06.S05" }, {}],
    ["wrong source microphase", { source_micro_phase_id: "RP00.P02.M05" }, {}],
    ["missing audit hint", { audit_hint: null }, {}],
    ["missing audit event ref", { audit_event_ref: "" }, {}],
    ["denied audit hint", { audit_hint_decision: "deny_blocked_claim_required" }, {}],
    ["unsatisfied audit event ref", { audit_event_ref_satisfied: false }, {}],
  ]) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(
        { ...baseAuditHintResult, ...resultOverride },
        claimOverride,
      ),
      Error,
      label,
    );
  }
  for (const claim of CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_PRIMARY_HAPPY_PATH_POLICY.forbiddenHappyPathClaims) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(baseAuditHintResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(baseAuditHintResult, { unexpected_happy_path_claim: true }),
    Error,
    "unknown claim",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(baseAuditHintResult, "bad-claims"),
    Error,
    "non-object claims",
  );
});

