test("Synthetic Fixture Set Secondary workflow path allows firm-level metadata and validator rejects drift", () => {
  const auditHintResult = precheckControlPlaneSyntheticFixtureSetAuditHint(
    createSyntheticFixtureSetPermissionResult({ matter_id: null }),
  );
  const primaryHappyPathResult = precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath(auditHintResult);
  const result = precheckControlPlaneSyntheticFixtureSetSecondaryWorkflowPath(primaryHappyPathResult);
  assert.equal(result.matter_id, null);
  assert.equal(result.secondary_workflow_receipt.matter_id, null);
  assert.equal(result.secondary_workflow_receipt.object_id, result.fixture_set_id);
  assert.equal(assertControlPlaneSyntheticFixtureSetSecondaryWorkflowPathResult(result), true);
  for (const [label, override] of [
    ["wrong marker", { secondary_workflow_path_subphase_id: "RP00.P02.M06.S07" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["fixture generation", { fixture_generation_permitted: true }],
    ["fixture persistence", { fixture_persistence_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.synthetic_fixture_set.secondary_workflow_path"] }],
    ["wrong receipt behavior", {
      secondary_workflow_receipt: {
        ...result.secondary_workflow_receipt,
        primary_happy_path_behavior_ref: "precheckControlPlaneSyntheticFixtureSetAuditHint",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneSyntheticFixtureSetPrimaryHappyPath" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M06.S08" }],
  ]) {
    assert.throws(
      () => assertControlPlaneSyntheticFixtureSetSecondaryWorkflowPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

