function createSyntheticFixtureSetStateTransitionEnforcementResult(overrides = {}, stateTransitionClaims = {}) {
  const result = precheckControlPlaneSyntheticFixtureSetStateTransitionEnforcement(
    createSyntheticFixtureSetSecondaryWorkflowPathResult(),
    stateTransitionClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

