test("Synthetic Fixture Set idempotency key handling accepts explicit synthetic keys and validator rejects drift", () => {
  const result = createSyntheticFixtureSetIdempotencyKeyHandlingResult(
    {},
    { idempotency_key: "idem.synthetic.synthetic_fixture_set.contract-validator:review-1" },
  );
  assert.equal(result.idempotency_key_source, "explicit_synthetic_claim");
  assert.equal(assertControlPlaneSyntheticFixtureSetIdempotencyKeyHandlingResult(result), true);
  for (const [label, override] of [
    ["wrong marker", { idempotency_key_handling_subphase_id: "RP00.P02.M06.S09" }],
    ["wrong scope", { idempotency_scope: "runtime_fixture_generation" }],
    ["invalid key", { idempotency_key: "idem.synthetic.Invalid" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["fixture generation", { fixture_generation_permitted: true }],
    ["fixture persistence", { fixture_persistence_permitted: true }],
    ["idempotency write", { idempotency_record_write_permitted: true }],
    ["store write", { idempotency_store_write_permitted: true }],
    ["lock acquisition", { lock_acquisition_permitted: true }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneSyntheticFixtureSetStateTransitionEnforcement" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M06.S10" }],
  ]) {
    assert.throws(
      () => assertControlPlaneSyntheticFixtureSetIdempotencyKeyHandlingResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Synthetic Fixture Set idempotency key handling fails closed on unsafe claims and wrong source", () => {
  const stateTransitionResult = createSyntheticFixtureSetStateTransitionEnforcementResult();
  for (const invalidStateTransitionResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(invalidStateTransitionResult),
      /requires S09 state transition enforcement result/,
      "missing state transition result",
    );
  }
  for (const claim of CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_IDEMPOTENCY_KEY_HANDLING_POLICY.forbiddenIdempotencyClaims) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(stateTransitionResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(stateTransitionResult, { write_idempotency_store: 0 }),
    /write_idempotency_store/,
    "falsy non-false forbidden idempotency claim",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(
      stateTransitionResult,
      { unreviewed_idempotency_claim: true },
    ),
    /unknown claim/,
    "unknown truthy idempotency claim",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(stateTransitionResult, { idempotency_key: "idem.synthetic.Invalid" }),
    /invalid idempotency_key characters/,
    "invalid idempotency key",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_enforcement_subphase_id: "RP00.P02.M06.S08",
    }),
    /requires RP00.P02.M06.S09 state transition enforcement result/,
    "wrong state transition marker",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      entrypoint_id: "permission_audit_binding",
    }),
    /requires synthetic_fixture_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_receipt: null,
    }),
    /requires S09 state transition enforcement result/,
    "missing state transition receipt",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied state transition",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling(stateTransitionResult, null),
    Error,
    "non-object claims",
  );
});

