test("Synthetic Fixture Set lock acquisition rule validator rejects drift", () => {
  const result = createSyntheticFixtureSetLockAcquisitionRuleResult();
  assert.equal(assertControlPlaneSyntheticFixtureSetLockAcquisitionRuleResult(result), true);
  for (const [label, override] of [
    ["wrong marker", { lock_acquisition_rule_subphase_id: "RP00.P02.M06.S10" }],
    ["wrong scope", { lock_scope: "runtime_fixture_lock" }],
    ["invalid key", { idempotency_key: "idem.synthetic.Invalid" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["fixture generation", { fixture_generation_permitted: true }],
    ["fixture persistence", { fixture_persistence_permitted: true }],
    ["idempotency write", { idempotency_record_write_permitted: true }],
    ["lock record write", { lock_record_write_permitted: true }],
    ["lock store write", { lock_store_write_permitted: true }],
    ["lock acquisition", { lock_acquisition_permitted: true }],
    ["UI", { ui_created: true }],
    ["source incomplete", { source_micro_phase_completed: false }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneSyntheticFixtureSetIdempotencyKeyHandling" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M06.S11" }],
  ]) {
    assert.throws(
      () => assertControlPlaneSyntheticFixtureSetLockAcquisitionRuleResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Synthetic Fixture Set lock acquisition rule fails closed on unsafe claims and wrong source", () => {
  const idempotencyResult = createSyntheticFixtureSetIdempotencyKeyHandlingResult();
  for (const invalidIdempotencyResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule(invalidIdempotencyResult),
      /requires S10 idempotency key handling result/,
      "missing idempotency result",
    );
  }
  for (const claim of CONTROL_PLANE_SYNTHETIC_FIXTURE_SET_LOCK_ACQUISITION_RULE_POLICY.forbiddenLockClaims) {
    assert.throws(
      () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule(idempotencyResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule(idempotencyResult, { persist_lock_record: 0 }),
    /persist_lock_record/,
    "falsy non-false forbidden lock claim",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule(
      idempotencyResult,
      { unreviewed_lock_claim: true },
    ),
    /unknown claim/,
    "unknown truthy lock claim",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_key_handling_subphase_id: "RP00.P02.M06.S09",
    }),
    /requires RP00.P02.M06.S10 idempotency key handling result/,
    "wrong idempotency marker",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule({
      ...idempotencyResult,
      entrypoint_id: "permission_audit_binding",
    }),
    /requires synthetic_fixture_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_receipt: null,
    }),
    /requires S10 idempotency key handling result/,
    "missing idempotency receipt",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied idempotency",
  );
  assert.throws(
    () => precheckControlPlaneSyntheticFixtureSetLockAcquisitionRule(idempotencyResult, null),
    Error,
    "non-object claims",
  );
});

