test("Test And Golden Case Set request normalization fails closed on unsafe inputs", () => {
  for (const [label, request] of [
    ["wrong entrypoint", createTestAndGoldenCaseSetRequestInput({ entrypoint_id: "synthetic_fixture_set" })],
    ["wrong source microphase", createTestAndGoldenCaseSetRequestInput({ source_micro_phase_id: "RP00.P02.M06" })],
    ["non production-ready contract", createTestAndGoldenCaseSetRequestInput({ service_entrypoint_contract_status: "draft" })],
    ["non production-ready fixture closeout", createTestAndGoldenCaseSetRequestInput({ synthetic_fixture_set_closeout_status: "draft" })],
    ["wrong fixture closeout ref", createTestAndGoldenCaseSetRequestInput({ synthetic_fixture_set_closeout_ref: "RP00.P02.M06.S10" })],
    ["wrong lock rule ref", createTestAndGoldenCaseSetRequestInput({ synthetic_fixture_set_lock_rule_ref: "RP00.P02.M06.S10" })],
    ["context drift", createTestAndGoldenCaseSetRequestInput({ test_and_golden_context_ids: CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_CONTEXT_IDS.slice(1) })],
    ["required evidence drift", createTestAndGoldenCaseSetRequestInput({ required_evidence_refs: CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_SERVICE_ENTRYPOINT_CONTRACT.requiredEvidenceRefs.slice(1) })],
    ["schema drift", createTestAndGoldenCaseSetRequestInput({ schema_expectation_fields: CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_SERVICE_ENTRYPOINT_CONTRACT.schemaExpectationFields.slice(1) })],
    ["acceptance gate drift", createTestAndGoldenCaseSetRequestInput({ acceptance_gate_ids: CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds.slice(1) })],
    ["catalog drift", createTestAndGoldenCaseSetRequestInput({ golden_case_catalog_ref: "RP00.P02.M07.wrong" })],
    ["unit test contract drift", createTestAndGoldenCaseSetRequestInput({ unit_test_contract_ref: "RP00.P02.M07.wrong" })],
    ["blank evidence ref", createTestAndGoldenCaseSetRequestInput({ command_evidence_ref: "" })],
  ]) {
    assert.throws(() => normalizeControlPlaneTestAndGoldenCaseSetRequest(request), Error, label);
  }
  for (const [label, claim] of [
    ["test execution", { execute_tests: true }],
    ["golden generation", { generate_golden_fixture: true }],
    ["golden persistence", { persist_golden_fixture: true }],
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["secret use", { use_credentials_or_secrets: true }],
    ["golden catalog mutation", { mutate_golden_case_catalog: true }],
    ["unit test contract mutation", { mutate_unit_test_contract: true }],
    ["source completion", { complete_source_micro_phase: true }],
    ["unknown claim", { unreviewed_golden_override: true }],
  ]) {
    assert.throws(
      () => normalizeControlPlaneTestAndGoldenCaseSetRequest(createTestAndGoldenCaseSetRequestInput(), claim),
      Error,
      label,
    );
  }
});

