test("Test And Golden Case Set Audit hint precheck fails closed on denied or unsafe audit claims", () => {
  for (const [label, resultOverride, claimOverride] of [
    ["non-test-and-golden entrypoint", { entrypoint_id: "synthetic_fixture_set" }, {}],
    ["wrong permission marker", { permission_precheck_subphase_id: "RP00.P02.M07.S04" }, {}],
    ["wrong source microphase", { source_micro_phase_id: "RP00.P02.M06" }, {}],
    ["missing permission decision ref satisfaction", { permission_decision_ref_satisfied: false }, {}],
    ["skip audit claim", {}, { skip_audit: true }],
    ["omit audit hint claim", {}, { omit_audit_hint: true }],
    ["write audit event claim", {}, { write_audit_event: true }],
    ["append audit ledger claim", {}, { append_audit_ledger: true }],
    ["mutate audit ledger claim", {}, { mutate_audit_ledger: true }],
    ["service execution claim", {}, { execute_service_logic: true }],
    ["product write claim", {}, { writes_product_state: true }],
    ["runtime route claim", {}, { create_runtime_route: true }],
    ["runtime permission claim", {}, { evaluate_runtime_permission: true }],
    ["AuthZ evaluator claim", {}, { call_authz_evaluator: true }],
    ["permission engine claim", {}, { run_permission_engine: true }],
    ["security trimming claim", {}, { apply_security_trimming: true }],
    ["test execution claim", {}, { execute_tests: true }],
    ["golden generation claim", {}, { generate_golden_fixture: true }],
    ["golden persistence claim", {}, { persist_golden_fixture: true }],
    ["database write claim", {}, { write_database: true }],
    ["storage write claim", {}, { write_storage: true }],
    ["product persistence claim", {}, { persist_product_state: true }],
    ["entity registry mutation claim", {}, { mutate_entity_registry: true }],
    ["golden catalog mutation claim", {}, { mutate_golden_case_catalog: true }],
    ["unit test contract mutation claim", {}, { mutate_unit_test_contract: true }],
    ["human approval replace claim", {}, { replace_human_approval: true }],
    ["human approval bypass claim", {}, { bypass_human_approval: true }],
    ["permission audit bypass claim", {}, { bypass_permission_audit: true }],
    ["permission bypass claim", {}, { bypass_permission: true }],
    ["audit hint bypass claim", {}, { bypass_audit_hint: true }],
    ["real client data claim", {}, { use_real_client_data: true }],
    ["real Matter data claim", {}, { use_real_matter_data: true }],
    ["secret use claim", {}, { use_credentials_or_secrets: true }],
    ["source completion claim", {}, { complete_source_micro_phase: true }],
    ["unknown truthy claim", {}, { unexpected_audit_claim: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetAuditHint(
        createTestAndGoldenCaseSetPermissionResult(resultOverride),
        claimOverride,
      ),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetAuditHint(createTestAndGoldenCaseSetPermissionResult(), "bad-claims"),
    Error,
    "non-object claims",
  );
});

