test("Test And Golden Case Set Primary happy path fails closed on unsafe claims and wrong source", () => {
  const baseAuditHintResult = createTestAndGoldenCaseSetAuditHintResult();
  for (const invalidAuditHintResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath(invalidAuditHintResult),
      /requires S06 audit hint precheck result/,
      "missing audit hint result",
    );
  }
  for (const [label, resultOverride] of [
    ["non-test-and-golden entrypoint", { entrypoint_id: "synthetic_fixture_set" }],
    ["wrong audit hint marker", { audit_hint_precheck_subphase_id: "RP00.P02.M07.S05" }],
    ["missing audit hint", { audit_hint: null }],
    ["missing audit event ref", { audit_event_ref: "" }],
    ["denied audit hint", { audit_hint_decision: "deny_blocked_claim_required" }],
    ["unsatisfied audit event ref", { audit_event_ref_satisfied: false }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath({ ...baseAuditHintResult, ...resultOverride }),
      Error,
      label,
    );
  }
  for (const claim of CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_PRIMARY_HAPPY_PATH_POLICY.forbiddenHappyPathClaims) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath(baseAuditHintResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath(baseAuditHintResult, { unexpected_happy_path_claim: true }),
    Error,
    "unknown claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath(baseAuditHintResult, "bad-claims"),
    Error,
    "non-object claims",
  );
});

