function createTestAndGoldenCaseSetStateTransitionEnforcementResult(overrides = {}, stateTransitionClaims = {}) {
  const result = precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(
    createTestAndGoldenCaseSetSecondaryWorkflowPathResult(),
    stateTransitionClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

