test("Test And Golden Case Set State transition enforcement rejects drift in no-write metadata", () => {
  const result = createTestAndGoldenCaseSetStateTransitionEnforcementResult();
  for (const [label, override] of [
    ["wrong marker", { state_transition_enforcement_subphase_id: "RP00.P02.M07.S08" }],
    ["wrong from", { state_transition_from: "primary_happy_path_ready" }],
    ["wrong to", { state_transition_to: "runtime_state_written" }],
    ["wrong rule", { state_transition_rule_ref: "test_and_golden_case_set.runtime_rule" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["test execution", { test_execution_permitted: true }],
    ["golden generation", { golden_fixture_generation_permitted: true }],
    ["golden persistence", { golden_fixture_persistence_permitted: true }],
    ["service logic", { service_logic_execution_permitted: true }],
    ["runtime route", { runtime_route_created: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product state persistence", { product_state_persistence_permitted: true }],
    ["real data flag", { no_real_data: false }],
    ["product write flag", { writes_product_state: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.test_and_golden_case_set.state_transition"] }],
    ["wrong receipt behavior", {
      state_transition_receipt: {
        ...result.state_transition_receipt,
        secondary_workflow_path_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetPrimaryHappyPath",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetSecondaryWorkflowPath" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M07.S09" }],
  ]) {
    assert.throws(
      () => assertControlPlaneTestAndGoldenCaseSetStateTransitionEnforcementResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Test And Golden Case Set State transition enforcement fails closed on unsafe claims and wrong source", () => {
  const secondaryWorkflowPathResult = createTestAndGoldenCaseSetSecondaryWorkflowPathResult();
  for (const invalidSecondaryWorkflowPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(invalidSecondaryWorkflowPathResult),
      /requires S08 secondary workflow path result/,
      "missing secondary workflow path result",
    );
  }
  for (const claim of CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_STATE_TRANSITION_ENFORCEMENT_POLICY.forbiddenStateTransitionClaims) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(secondaryWorkflowPathResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(secondaryWorkflowPathResult, { unexpected_state_transition_claim: true }),
    /unknown claim/,
    "unknown truthy state transition claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(
      secondaryWorkflowPathResult,
      { state_transition_from: "primary_happy_path_ready" },
    ),
    /invalid state transition/,
    "invalid transition from",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_subphase_id: "RP00.P02.M07.S07",
    }),
    /requires RP00.P02.M07.S08 secondary workflow path result/,
    "wrong secondary marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      entrypoint_id: "synthetic_fixture_set",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_receipt: null,
    }),
    /requires S08 secondary workflow path result/,
    "missing secondary workflow receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      audit_event_ref: "",
    }),
    /requires S08 secondary workflow path result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied secondary workflow",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement({
      ...secondaryWorkflowPathResult,
      secondary_workflow_path_applied: false,
    }),
    Error,
    "unapplied secondary workflow",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement(secondaryWorkflowPathResult, "bad-claims"),
    Error,
    "non-object claims",
  );
});

