test("Test And Golden Case Set Idempotency key handling accepts explicit synthetic keys and validator rejects drift", () => {
  const result = createTestAndGoldenCaseSetIdempotencyKeyHandlingResult(
    {},
    { idempotency_key: "idem.synthetic.test_and_golden_case_set.contract-validator:review-1" },
  );
  assert.equal(result.idempotency_key_source, "explicit_synthetic_claim");
  assert.equal(assertControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandlingResult(result), true);
  for (const [label, override] of [
    ["wrong marker", { idempotency_key_handling_subphase_id: "RP00.P02.M07.S09" }],
    ["wrong scope", { idempotency_scope: "runtime_test_execution" }],
    ["invalid key", { idempotency_key: "idem.synthetic.Invalid" }],
    ["wrong key source", { idempotency_key_source: "runtime_claim" }],
    ["wrong ttl", { idempotency_ttl_policy_ref: "runtime_ttl" }],
    ["wrong duplicate policy", { duplicate_replay_policy: "execute_duplicate" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["test execution", { test_execution_permitted: true }],
    ["golden generation", { golden_fixture_generation_permitted: true }],
    ["golden persistence", { golden_fixture_persistence_permitted: true }],
    ["service logic", { service_logic_execution_permitted: true }],
    ["runtime route", { runtime_route_created: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product state persistence", { product_state_persistence_permitted: true }],
    ["idempotency write", { idempotency_record_write_permitted: true }],
    ["store write", { idempotency_store_write_permitted: true }],
    ["lock acquisition", { lock_acquisition_permitted: true }],
    ["real data flag", { no_real_data: false }],
    ["product write flag", { writes_product_state: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.test_and_golden_case_set.idempotency"] }],
    ["wrong receipt behavior", {
      idempotency_receipt: {
        ...result.idempotency_receipt,
        state_transition_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetSecondaryWorkflowPath",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M07.S10" }],
  ]) {
    assert.throws(
      () => assertControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandlingResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Test And Golden Case Set Idempotency key handling fails closed on unsafe claims and wrong source", () => {
  const stateTransitionResult = createTestAndGoldenCaseSetStateTransitionEnforcementResult();
  for (const invalidStateTransitionResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(invalidStateTransitionResult),
      /requires S09 state transition enforcement result/,
      "missing state transition result",
    );
  }
  for (const claim of CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_IDEMPOTENCY_KEY_HANDLING_POLICY.forbiddenIdempotencyClaims) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(stateTransitionResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(stateTransitionResult, { write_idempotency_store: 0 }),
    /write_idempotency_store/,
    "falsy non-false forbidden idempotency claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(
      stateTransitionResult,
      { unreviewed_idempotency_claim: true },
    ),
    /unknown claim/,
    "unknown truthy idempotency claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(stateTransitionResult, { idempotency_key: "idem.synthetic.Invalid" }),
    /invalid idempotency_key characters/,
    "invalid idempotency key",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_enforcement_subphase_id: "RP00.P02.M07.S08",
    }),
    /requires RP00.P02.M07.S09 state transition enforcement result/,
    "wrong state transition marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      entrypoint_id: "synthetic_fixture_set",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_receipt: null,
    }),
    /requires S09 state transition enforcement result/,
    "missing state transition receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      audit_event_ref: "",
    }),
    /requires S09 state transition enforcement result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied state transition",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling({
      ...stateTransitionResult,
      state_transition_enforcement_applied: false,
    }),
    Error,
    "unapplied state transition",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling(stateTransitionResult, "bad-claims"),
    Error,
    "non-object claims",
  );
});

