test("Test And Golden Case Set Lock acquisition rule validator rejects drift", () => {
  const result = createTestAndGoldenCaseSetLockAcquisitionRuleResult();
  assert.equal(assertControlPlaneTestAndGoldenCaseSetLockAcquisitionRuleResult(result), true);
  for (const [label, override] of [
    ["wrong marker", { lock_acquisition_rule_subphase_id: "RP00.P02.M07.S10" }],
    ["wrong scope", { lock_scope: "runtime_lock" }],
    ["wrong rule", { lock_rule_ref: "runtime.lock" }],
    ["wrong contention", { lock_contention_policy: "wait_for_lock" }],
    ["wrong ownership", { lock_ownership_policy_ref: "runtime_owner" }],
    ["runtime permission", { runtime_permission_evaluation_permitted: true }],
    ["AuthZ call", { authz_evaluator_call_permitted: true }],
    ["permission engine", { permission_engine_execution_permitted: true }],
    ["security trimming", { security_trimming_execution_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["test execution", { test_execution_permitted: true }],
    ["golden generation", { golden_fixture_generation_permitted: true }],
    ["golden persistence", { golden_fixture_persistence_permitted: true }],
    ["service logic", { service_logic_execution_permitted: true }],
    ["runtime route", { runtime_route_created: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product state persistence", { product_state_persistence_permitted: true }],
    ["idempotency write", { idempotency_record_write_permitted: true }],
    ["idempotency store write", { idempotency_store_write_permitted: true }],
    ["lock record write", { lock_record_write_permitted: true }],
    ["lock store write", { lock_store_write_permitted: true }],
    ["lock acquisition", { lock_acquisition_permitted: true }],
    ["ui created", { ui_created: true }],
    ["source complete", { source_micro_phase_completed: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.test_and_golden_case_set.lock"] }],
    ["wrong receipt behavior", {
      lock_receipt: {
        ...result.lock_receipt,
        idempotency_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetStateTransitionEnforcement",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneTestAndGoldenCaseSetIdempotencyKeyHandling" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M07.S11" }],
  ]) {
    assert.throws(
      () => assertControlPlaneTestAndGoldenCaseSetLockAcquisitionRuleResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Test And Golden Case Set Lock acquisition rule fails closed on unsafe claims and wrong source", () => {
  const idempotencyResult = createTestAndGoldenCaseSetIdempotencyKeyHandlingResult();
  for (const invalidIdempotencyResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule(invalidIdempotencyResult),
      /requires S10 idempotency key handling result/,
      "missing idempotency result",
    );
  }
  for (const claim of CONTROL_PLANE_TEST_AND_GOLDEN_CASE_SET_LOCK_ACQUISITION_RULE_POLICY.forbiddenLockClaims) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule(idempotencyResult, { [claim]: true }),
      Error,
      claim,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule(idempotencyResult, { persist_lock_record: 0 }),
    /persist_lock_record/,
    "falsy non-false forbidden lock claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule(
      idempotencyResult,
      { unreviewed_lock_override: true },
    ),
    /unknown claim/,
    "unknown truthy lock claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_key_handling_subphase_id: "RP00.P02.M07.S09",
    }),
    /requires RP00.P02.M07.S10 idempotency key handling result/,
    "wrong idempotency marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      entrypoint_id: "synthetic_fixture_set",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_receipt: null,
    }),
    /requires S10 idempotency key handling result/,
    "missing idempotency receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      audit_event_ref: "",
    }),
    /requires S10 idempotency key handling result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied idempotency result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_key_handling_applied: false,
    }),
    Error,
    "unapplied idempotency result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetLockAcquisitionRule(idempotencyResult, null),
    Error,
    "non-object claims",
  );
});

