test("Test And Golden Case Set Persistence boundary validator rejects drift", () => {
  const result = precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(createTestAndGoldenCaseSetLockAcquisitionRuleResult());
  for (const [label, override] of [
    ["not applied", { persistence_boundary_applied: false }],
    ["wrong marker", { persistence_boundary_subphase_id: "RP00.P02.M07.S11" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["test execution", { test_execution_permitted: true }],
    ["golden generation", { golden_fixture_generation_permitted: true }],
    ["golden persistence", { golden_fixture_persistence_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product persistence", { product_state_persistence_permitted: true }],
    ["persistence record write", { persistence_record_write_permitted: true }],
    ["persistence store write", { persistence_store_write_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.test_and_golden.persistence"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M07.S12" }],
  ]) {
    assert.throws(
      () => assertControlPlaneTestAndGoldenCaseSetPersistenceBoundaryResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Test And Golden Case Set Persistence boundary fails closed on unsafe claims and wrong source", () => {
  const lockResult = createTestAndGoldenCaseSetLockAcquisitionRuleResult();
  for (const invalidLockResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(invalidLockResult),
      /requires S11 lock acquisition rule result/,
      "missing lock acquisition rule result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["object store write", { write_object_store: true }],
    ["test execution", { execute_tests: true }],
    ["golden generation", { generate_golden_fixture: true }],
    ["golden persistence", { persist_golden_fixture: true }],
    ["golden catalog mutation", { mutate_golden_case_catalog: true }],
    ["unit test contract mutation", { mutate_unit_test_contract: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["persistence boundary bypass", { bypass_persistence_boundary: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["secret use", { use_credentials_or_secrets: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(lockResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(lockResult, { write_database: 0 }),
    /write_database/,
    "falsy non-false forbidden persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(lockResult, { unreviewed_persistence_override: true }),
    /unknown claim/,
    "unknown truthy persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary({
      ...lockResult,
      lock_acquisition_rule_subphase_id: "RP00.P02.M07.S10",
    }),
    /requires RP00.P02.M07.S11 lock acquisition rule result/,
    "wrong lock marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary({
      ...lockResult,
      entrypoint_id: "synthetic_fixture_set",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary({
      ...lockResult,
      lock_receipt: null,
    }),
    /requires S11 lock acquisition rule result/,
    "missing lock receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary({
      ...lockResult,
      audit_event_ref: "",
    }),
    /requires S11 lock acquisition rule result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary({
      ...lockResult,
      lock_acquisition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied lock result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetPersistenceBoundary(lockResult, null),
    Error,
    "non-object claims",
  );
});

