function createTestAndGoldenCaseSetApprovalRequiredRoutingResult(overrides = {}, approvalRequiredClaims = {}) {
  const result = precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(
    createTestAndGoldenCaseSetReviewRequiredRoutingResult(),
    approvalRequiredClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

