test("Test And Golden Case Set Approval-required routing fails closed on unsafe claims and wrong source", () => {
  const reviewRoutingResult = createTestAndGoldenCaseSetReviewRequiredRoutingResult();
  for (const invalidReviewRoutingResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(invalidReviewRoutingResult),
      /requires S14 review-required routing result/,
      "missing review-required routing result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["Claude runtime review", { invoke_claude_runtime_review: true }],
    ["review queue write", { write_review_queue: true }],
    ["review assignment write", { write_review_assignment: true }],
    ["review notification write", { write_review_notification: true }],
    ["execute tests", { execute_tests: true }],
    ["generate golden fixture", { generate_golden_fixture: true }],
    ["persist golden fixture", { persist_golden_fixture: true }],
    ["mutate golden catalog", { mutate_golden_case_catalog: true }],
    ["mutate unit-test contract", { mutate_unit_test_contract: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["error store write", { write_error_store: true }],
    ["create approval queue item", { create_approval_queue_item: true }],
    ["write approval queue", { write_approval_queue: true }],
    ["assign approver", { assign_approver: true }],
    ["notify approver", { notify_approver: true }],
    ["write approval record", { write_approval_record: true }],
    ["write human approval record", { write_human_approval_record: true }],
    ["approve human approval", { approve_human_approval: true }],
    ["render approval UI", { render_approval_ui: true }],
    ["approval-required bypass", { bypass_approval_required_routing: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(reviewRoutingResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(reviewRoutingResult, { write_approval_queue: 0 }),
    /write_approval_queue/,
    "falsy non-false forbidden approval-required claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(reviewRoutingResult, { unexpected_approval_required_claim: true }),
    /unknown claim/,
    "unknown truthy approval-required claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting({
      ...reviewRoutingResult,
      review_required_routing_subphase_id: "RP00.P02.M07.S13",
    }),
    /requires RP00.P02.M07.S14 review-required routing result/,
    "wrong review-required routing marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting({
      ...reviewRoutingResult,
      entrypoint_id: "permission_audit_binding",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting({
      ...reviewRoutingResult,
      review_required_receipt: null,
    }),
    /requires S14 review-required routing result/,
    "missing review-required receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting({
      ...reviewRoutingResult,
      review_required_ref: "",
    }),
    /requires S14 review-required routing result/,
    "missing review-required ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting({
      ...reviewRoutingResult,
      review_required_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied review-required routing result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetApprovalRequiredRouting(reviewRoutingResult, null),
    Error,
    "non-object claims",
  );
});

