test("Test And Golden Case Set Blocked-claim output fails closed on unsafe claims and wrong source", () => {
  const approvalRoutingResult = createTestAndGoldenCaseSetApprovalRequiredRoutingResult();
  for (const invalidApprovalRoutingResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput(invalidApprovalRoutingResult),
      /requires S15 approval-required routing result/,
      "missing approval-required routing result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["Claude runtime review", { invoke_claude_runtime_review: true }],
    ["review queue write", { write_review_queue: true }],
    ["review assignment write", { write_review_assignment: true }],
    ["review notification write", { write_review_notification: true }],
    ["approval queue write", { write_approval_queue: true }],
    ["approval record write", { write_approval_record: true }],
    ["human approval record write", { write_human_approval_record: true }],
    ["execute tests", { execute_tests: true }],
    ["generate golden fixture", { generate_golden_fixture: true }],
    ["persist golden fixture", { persist_golden_fixture: true }],
    ["mutate golden catalog", { mutate_golden_case_catalog: true }],
    ["mutate unit-test contract", { mutate_unit_test_contract: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["error store write", { write_error_store: true }],
    ["blocked output write", { write_blocked_claim_output: true }],
    ["blocked record write", { write_blocked_claim_record: true }],
    ["blocked notification", { notify_blocked_claim_owner: true }],
    ["blocked UI", { render_blocked_claim_ui: true }],
    ["blocked refs mutation", { mutate_blocked_claim_refs: true }],
    ["blocked output bypass", { bypass_blocked_claim_output: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput(approvalRoutingResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput(approvalRoutingResult, { write_blocked_claim_output: 0 }),
    /write_blocked_claim_output/,
    "falsy non-false forbidden blocked-claim output claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput(approvalRoutingResult, { unexpected_blocked_claim_output_claim: true }),
    /unknown claim/,
    "unknown truthy blocked-claim output claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput({
      ...approvalRoutingResult,
      approval_required_routing_subphase_id: "RP00.P02.M07.S14",
    }),
    /requires RP00.P02.M07.S15 approval-required routing result/,
    "wrong approval-required routing marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput({
      ...approvalRoutingResult,
      entrypoint_id: "permission_audit_binding",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput({
      ...approvalRoutingResult,
      approval_required_receipt: null,
    }),
    /requires S15 approval-required routing result/,
    "missing approval-required receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput({
      ...approvalRoutingResult,
      approval_required_ref: "",
    }),
    /requires S15 approval-required routing result/,
    "missing approval-required ref",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput({
      ...approvalRoutingResult,
      approval_required_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied approval-required routing result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetBlockedClaimOutput(approvalRoutingResult, null),
    Error,
    "non-object claims",
  );
});

