test("Test And Golden Case Set rollback behavior fails closed on unsafe claims and wrong source", () => {
  const blockedClaimOutputResult = createTestAndGoldenCaseSetBlockedClaimOutputResult();
  for (const invalidBlockedClaimOutputResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior(invalidBlockedClaimOutputResult),
      /requires S16 blocked-claim output result/,
      "missing blocked-claim output result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["Claude runtime review", { invoke_claude_runtime_review: true }],
    ["review queue write", { write_review_queue: true }],
    ["approval queue write", { write_approval_queue: true }],
    ["approval record write", { write_approval_record: true }],
    ["human approval record write", { write_human_approval_record: true }],
    ["execute tests", { execute_tests: true }],
    ["generate golden fixture", { generate_golden_fixture: true }],
    ["persist golden fixture", { persist_golden_fixture: true }],
    ["mutate golden catalog", { mutate_golden_case_catalog: true }],
    ["mutate unit-test contract", { mutate_unit_test_contract: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission engine", { run_permission_engine: true }],
    ["security trimming", { apply_security_trimming: true }],
    ["error store write", { write_error_store: true }],
    ["blocked output write", { write_blocked_claim_output: true }],
    ["blocked record write", { write_blocked_claim_record: true }],
    ["blocked notification", { notify_blocked_claim_owner: true }],
    ["execute rollback", { execute_rollback: true }],
    ["run rollback", { run_rollback: true }],
    ["write rollback state", { write_rollback_state: true }],
    ["persist rollback plan", { persist_rollback_plan: true }],
    ["enqueue retry", { enqueue_retry: true }],
    ["execute retry", { execute_retry: true }],
    ["run compensation", { run_compensation: true }],
    ["write compensation record", { write_compensation_record: true }],
    ["notify operator", { notify_operator: true }],
    ["notify customer", { notify_customer: true }],
    ["create incident trace", { create_incident_trace: true }],
    ["write incident trace", { write_incident_trace: true }],
    ["append observability event", { append_observability_event: true }],
    ["rollback bypass", { bypass_rollback_behavior: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior(blockedClaimOutputResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior(blockedClaimOutputResult, { execute_rollback: 0 }),
    /execute_rollback/,
    "falsy non-false forbidden rollback behavior claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior(blockedClaimOutputResult, { unexpected_rollback_behavior_claim: true }),
    /unknown claim/,
    "unknown truthy rollback behavior claim",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_subphase_id: "RP00.P02.M07.S15",
    }),
    /requires RP00.P02.M07.S16 blocked-claim output result/,
    "wrong blocked-claim output marker",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior({
      ...blockedClaimOutputResult,
      entrypoint_id: "permission_audit_binding",
    }),
    /requires test_and_golden_case_set entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_receipt: null,
    }),
    /requires S16 blocked-claim output result/,
    "missing blocked-claim receipt",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_refs: [],
    }),
    /requires S16 blocked-claim output result/,
    "missing blocked claim refs",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior({
      ...blockedClaimOutputResult,
      blocked_claim_output_decision: "deny_rollback_required",
    }),
    Error,
    "denied blocked-claim output result",
  );
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRollbackBehavior(blockedClaimOutputResult, null),
    Error,
    "non-object claims",
  );
});

