function createTestAndGoldenCaseSetRetryBehaviorResult(overrides = {}, retryBehaviorClaims = {}) {
  const result = precheckControlPlaneTestAndGoldenCaseSetRetryBehavior(
    createTestAndGoldenCaseSetRollbackBehaviorResult(),
    retryBehaviorClaims,
  );
  return Object.keys(overrides).length === 0 ? result : { ...result, ...overrides };
}

