function assertTestAndGoldenCaseSetDeniedPathCaseThrows(testCase, rollbackBehaviorResult) {
  const input = testCase.type === "input_drift"
    ? { ...rollbackBehaviorResult, ...testCase.override }
    : rollbackBehaviorResult;
  const claims = testCase.claimsNull === true
    ? null
    : testCase.claim
      ? { [testCase.claim]: testCase.claimValue }
      : {};
  assert.throws(
    () => precheckControlPlaneTestAndGoldenCaseSetRetryBehavior(input, claims),
    Error,
    testCase.id,
  );
}

