test("API Evidence And Handoff boundary suite fails closed on tenant drift and unsafe claims", () => {
  const denied = assembleControlPlaneApiEvidenceHandoffBoundarySuite(createApiEvidenceHandoffInput({
    matter_tenant_id: "tenant.synthetic.other",
  }));
  assert.equal(assertControlPlaneApiEvidenceHandoffBoundarySuiteResult(denied), true);
  assert.equal(denied.api_evidence_handoff_state_transition, "blocked");
  assert.equal(denied.synthetic_fixture_surface_bound, false);
  assert.equal(denied.test_golden_case_surface_bound, false);
  assert.equal(denied.hermes_evidence_packet_surface_bound, false);
  assert.equal(denied.claude_review_packet_surface_bound, false);
  assert.equal(denied.closeout_handoff_surface_bound, false);
  assert.equal(denied.unauthorized_data_omitted, false);
  assert.equal(denied.hidden_policy_internals_omitted, false);
  assert.equal(denied.source_micro_phases_completed, false);
  assert.ok(denied.blocked_claim_refs.includes("blocked.synthetic.api_evidence_handoff.cross_tenant_boundary"));
  assert.throws(
    () => assertControlPlaneApiEvidenceHandoffBoundarySuiteResult({
      ...denied,
      source_micro_phases_completed: true,
    }),
    /completion triplet mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneApiEvidenceHandoffBoundarySuite(createApiEvidenceHandoffInput(), { invoke_hermes_runtime: true }),
    /cannot claim invoke_hermes_runtime/,
  );
  assert.throws(
    () => assembleControlPlaneApiEvidenceHandoffBoundarySuite(createApiEvidenceHandoffInput(), { surprise_claim: true }),
    /cannot accept unknown claim surprise_claim/,
  );
});

