test("UI Operator Surface Test And Golden Case Set boundary fails closed on upstream block and unsafe claims", () => {
  const deniedUpstream = createUiOperatorSurfaceSyntheticFixtureSetResult({}, {}, {}, { matter_tenant_id: "tenant.synthetic.other" });
  const denied = assembleControlPlaneUiOperatorSurfaceTestGoldenCaseSet(deniedUpstream);
  assert.equal(assertControlPlaneUiOperatorSurfaceTestGoldenCaseSetResult(denied), true);
  assert.equal(denied.test_golden_case_set_decision, "blocked");
  assert.equal(denied.test_case_count, 0);
  assert.equal(denied.synthetic_fixture_set_bound, false);
  assert.equal(denied.source_micro_phase_completed, false);
  assert.ok(denied.blocked_claim_refs.includes("blocked.synthetic.ui_operator_surface_test_golden_case_set.upstream_fixture_set_not_bound"));
  assert.throws(
    () => assertControlPlaneUiOperatorSurfaceTestGoldenCaseSetResult({
      ...denied,
      source_micro_phase_completed: true,
    }),
    /completion triplet mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneUiOperatorSurfaceTestGoldenCaseSet(createUiOperatorSurfaceSyntheticFixtureSetResult({
      pack_id: "CP00-062-old",
    })),
    /pack_id mismatch|pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneUiOperatorSurfaceTestGoldenCaseSet(createUiOperatorSurfaceSyntheticFixtureSetResult({
      next_subphase: "RP00.P04.M06.S08",
    })),
    /next_subphase mismatch|requires RP00.P04.M07.S01 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneUiOperatorSurfaceTestGoldenCaseSet(createUiOperatorSurfaceSyntheticFixtureSetResult(), { execute_runtime_test: true }),
    /cannot claim execute_runtime_test/,
  );
  assert.throws(
    () => assembleControlPlaneUiOperatorSurfaceTestGoldenCaseSet(createUiOperatorSurfaceSyntheticFixtureSetResult(), { surprise_claim: true }),
    /cannot accept unknown claim surprise_claim/,
  );
});

