test("Permission Audit Review Approval Secondary Matrix fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput({ pack_id: "CP00-070-drift" }),
    ),
    /pack.*mismatch/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput({ next_subphase: "RP00.P06.M04.S04" }),
    ),
    /next_subphase mismatch|RP00\.P06\.M03\.S14 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput({ primary_action_boundary_bound: false }),
    ),
    /primary_action_boundary_bound must be true|completed CP00-070 primary action boundary/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput(),
      { run_security_trimming: true },
    ),
    /cannot claim run_security_trimming/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput(),
      { unplanned_review_route: true },
    ),
    /cannot accept unknown claim unplanned_review_route/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditReviewApprovalSecondaryMatrix(
      createPermissionAuditReviewApprovalSecondaryMatrixInput(),
      [],
    ),
    /claims must be an object/,
  );
});

