test("Permission Audit Binding Initial Matrix fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput({ pack_id: "CP00-072-drift" }),
    ),
    /pack.*mismatch/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput({ next_subphase: "RP00.P06.M05.S10" }),
    ),
    /next_subphase mismatch|RP00\.P06\.M04\.S14 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput({ secondary_workflow_guard_bound: false }),
    ),
    /secondary_workflow_guard_bound must be true|completed CP00-072 secondary workflow guard boundary/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput(),
      { execute_permission_audit_binding_mutation: true },
    ),
    /cannot claim execute_permission_audit_binding_mutation/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput(),
      { unplanned_initial_matrix: true },
    ),
    /cannot accept unknown claim unplanned_initial_matrix/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditBindingInitialMatrix(
      createPermissionAuditBindingInitialMatrixInput(),
      [],
    ),
    /claims must be an object/,
  );
});

