test("Permission Audit Synthetic Fixture Decision Binding fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput({ pack_id: "CP00-074-drift" }),
    ),
    /pack.*mismatch/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput({ next_subphase: "RP00.P06.M06.S09" }),
    ),
    /next_subphase mismatch|RP00\.P06\.M05\.S20 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput({ allowed_test_bound: false }),
    ),
    /allowed_test_bound must be true|completed CP00-074 interaction proof boundary/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput(),
      { execute_denied_test: true },
    ),
    /cannot claim execute_denied_test/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput(),
      { unplanned_synthetic_fixture_decision: true },
    ),
    /cannot accept unknown claim unplanned_synthetic_fixture_decision/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditSyntheticFixtureDecisionBinding(
      createPermissionAuditSyntheticFixtureDecisionBindingInput(),
      [],
    ),
    /claims must be an object/,
  );
});

