test("Permission Audit Hermes Evidence Packet Decision Binding fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput({ pack_id: "CP00-077-drift" }),
    ),
    /pack.*mismatch/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput({ next_subphase: "RP00.P06.M07.S18" }),
    ),
    /next_subphase mismatch|RP00\.P06\.M07\.S19 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput({ audit_event_expectation_bound: false }),
    ),
    /audit_event_expectation_bound must be true|completed CP00-077 interaction set boundary/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput(),
      { write_hermes_evidence_packet: true },
    ),
    /cannot claim write_hermes_evidence_packet/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput(),
      { unexpected_evidence_claim: true },
    ),
    /cannot accept unknown claim unexpected_evidence_claim/,
  );
  assert.throws(
    () => assembleControlPlanePermissionAuditHermesEvidencePacketDecisionBinding(
      createPermissionAuditHermesEvidencePacketDecisionBindingInput(),
      [],
    ),
    /claims must be an object/,
  );
});

