test("Failure Edge Recovery Opening fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryOpening(
      createFailureEdgeRecoveryOpeningInput({ pack_id: "CP00-080-drift" }),
    ),
    /pack.*mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryOpening(
      createFailureEdgeRecoveryOpeningInput({ next_subphase: "RP00.P06.M10.S03" }),
    ),
    /next_subphase mismatch|RP00\.P07\.M00\.S01 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryOpening(
      createFailureEdgeRecoveryOpeningInput({ phase_completed: false }),
    ),
    /completed CP00-080 permission audit closeout boundary|phase_completed mismatch|phase_completed must be true/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryOpening(
      createFailureEdgeRecoveryOpeningInput(),
      { emit_runtime_error_response: true },
    ),
    /cannot claim emit_runtime_error_response/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryOpening(
      createFailureEdgeRecoveryOpeningInput(),
      { unexpected_failure_claim: true },
    ),
    /cannot accept unknown claim unexpected_failure_claim/,
  );
});

