  assert.equal(result.missing_actor_failure_bound, true);
  assert.equal(result.missing_matter_failure_bound, true);
  assert.equal(result.missing_resource_failure_bound, true);
  assert.equal(result.unknown_action_failure_bound, true);
  assert.equal(result.cross_tenant_failure_bound, true);
  assert.equal(result.permission_denied_failure_bound, true);
  assert.equal(result.ambiguous_rule_failure_bound, true);
  assert.equal(result.stale_reference_failure_bound, true);
  assert.deepEqual(result.completed_source_micro_phase_ids, ["RP00.P07.M03", "RP00.P07.M04"]);
  assert.deepEqual(result.partially_completed_source_micro_phase_ids, ["RP00.P07.M05"]);
  assert.deepEqual(result.open_source_micro_phase_ids, ["RP00.P07.M05"]);
