test("Failure Edge Recovery Permission Audit Failure Taxonomy fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput({ pack_id: "CP00-083-drift" }),
    ),
    /Failure Edge Recovery Permission Audit Failure Taxonomy upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput({ planned_pack_id: "CP00-083-drift" }),
    ),
    /Failure Edge Recovery Permission Audit Failure Taxonomy upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput({ next_subphase: "RP00.P07.M05.S02" }),
    ),
    /Failure Edge Recovery Permission Audit Failure Taxonomy requires RP00\.P07\.M05\.S01 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput({ failure_edge_recovery_secondary_workflow_decision: "runtime_permission_eval_started" }),
    ),
    /Failure Edge Recovery Permission Audit Failure Taxonomy requires completed CP00-083 secondary workflow boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput(),
      { evaluate_permission_audit_failure: true },
    ),
    /cannot claim evaluate_permission_audit_failure/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput(),
      { write_permission_audit_failure_audit_event: true },
    ),
    /cannot claim write_permission_audit_failure_audit_event/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput(),
      { start_ldip_implementation: true },
    ),
    /cannot claim start_ldip_implementation/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput(),
      { unexpected_permission_audit_failure_claim: true },
    ),
    /cannot accept unknown claim unexpected_permission_audit_failure_claim/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(null),
    /secondary workflow result must be an object/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditFailureTaxonomy(
      createFailureEdgeRecoveryPermissionAuditFailureTaxonomyInput(),
      "bad-claims",
    ),
    /claims must be an object/,
  );
});

