test("Failure Edge Recovery Permission Audit Recovery Evidence assembles metadata-only recovery evidence", () => {
  const result = assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
    createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
  );
  assert.equal(assertControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidenceResult(result), true);
  assert.equal(Object.isFrozen(result), true);
  assert.equal(Object.isFrozen(result.included_unit_ids), true);
  assert.equal(Object.isFrozen(result.permission_audit_recovery_failure_contracts), true);
  assert.equal(Object.isFrozen(result.permission_audit_recovery_failure_contracts[0]), true);
  assert.equal(Object.isFrozen(result.permission_audit_recovery_expectation_contracts), true);
  assert.equal(Object.isFrozen(result.blocked_claim_receipt_contract), true);
  assert.equal(Object.isFrozen(result.blocked_claim_receipt_contract.required_blocked_claims), true);
  assert.equal(result.failure_edge_recovery_permission_audit_recovery_evidence_decision, "failure_edge_recovery_permission_audit_recovery_evidence_bound_metadata_only");
  assert.deepEqual(result.included_unit_ids, CONTROL_PLANE_FAILURE_EDGE_RECOVERY_PERMISSION_AUDIT_RECOVERY_EVIDENCE_SUBPHASE_IDS);
  assert.equal(result.upstream_failure_edge_recovery_permission_audit_failure_taxonomy_consumed, true);
  assert.equal(result.permission_audit_binding_recovery_evidence_bound, true);
  assert.equal(result.lock_conflict_failure_bound, true);
  assert.equal(result.retry_exhaustion_failure_bound, true);
  assert.equal(result.rollback_expectation_bound, true);
  assert.equal(result.compensation_expectation_bound, true);
  assert.equal(result.blocked_claim_receipt_bound, true);
  assert.equal(result.failure_fixture_bound, true);
  assert.equal(result.failure_unit_test_bound, true);
  assert.equal(result.failure_integration_smoke_bound, true);
  assert.equal(result.audit_failure_hint_bound, true);
  assert.equal(result.hermes_failure_evidence_bound, true);
  assert.deepEqual(result.completed_source_micro_phase_ids, ["RP00.P07.M03", "RP00.P07.M04", "RP00.P07.M05"]);
  assert.deepEqual(result.partially_completed_source_micro_phase_ids, []);
  assert.deepEqual(result.open_source_micro_phase_ids, ["RP00.P07.M06"]);
  assert.equal(result.permission_audit_recovery_failure_contracts.length, 2);
  assert.equal(result.permission_audit_recovery_expectation_contracts.length, 2);
  assert.equal(result.failure_test_contracts.length, 2);
  assert.equal(result.runtime_retry_execution_permitted, false);
  assert.equal(result.runtime_rollback_execution_permitted, false);
  assert.equal(result.runtime_compensation_execution_permitted, false);
  assert.equal(result.runtime_lock_acquisition_permitted, false);
  assert.equal(result.audit_event_write_permitted, false);
  assert.equal(result.ldip_implementation_allowed, false);
  assert.equal(result.no_real_data, true);
  assert.equal(result.writes_product_state, false);
  assert.equal(result.source_micro_phase_completed, true);
  assert.equal(result.phase_completed, false);
  assert.equal(result.next_subphase, "RP00.P07.M06.S01");
  assert.throws(
    () => assertControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidenceResult({
      ...result,
      runtime_retry_execution_permitted: true,
    }),
    /runtime_retry_execution_permitted mismatch/,
  );
  assert.throws(
    () => assertControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidenceResult({
      ...result,
      unexpected_runtime_boundary: false,
    }),
    /must not contain extra fields/,
  );
});

