test("Failure Edge Recovery Permission Audit Recovery Evidence fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ pack_id: "CP00-084-drift" }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ planned_pack_id: "CP00-084-drift" }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ next_subphase: "RP00.P07.M05.S12" }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence requires RP00\.P07\.M05\.S11 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ failure_edge_recovery_permission_audit_failure_taxonomy_decision: "runtime_recovery_started" }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence requires completed CP00-084 permission audit failure taxonomy boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ runtime_retry_execution_permitted: true }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence requires completed CP00-084 permission audit failure taxonomy boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput({ permission_audit_binding_failure_taxonomy_bound: false }),
    ),
    /Failure Edge Recovery Permission Audit Recovery Evidence requires completed CP00-084 permission audit failure taxonomy boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
      { execute_permission_audit_retry: true },
    ),
    /cannot claim execute_permission_audit_retry/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
      { write_permission_audit_recovery_audit_event: true },
    ),
    /cannot claim write_permission_audit_recovery_audit_event/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
      { start_ldip_implementation: true },
    ),
    /cannot claim start_ldip_implementation/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
      { unexpected_permission_audit_recovery_claim: true },
    ),
    /cannot accept unknown claim unexpected_permission_audit_recovery_claim/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(null),
    /failure taxonomy result must be an object/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoveryPermissionAuditRecoveryEvidence(
      createFailureEdgeRecoveryPermissionAuditRecoveryEvidenceInput(),
      "bad-claims",
    ),
    /claims must be an object/,
  );
});

