test("Failure Edge Recovery Synthetic Fixture Set fails closed on drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput({ pack_id: "CP00-085-drift" }),
    ),
    /Failure Edge Recovery Synthetic Fixture Set upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput({ planned_pack_id: "CP00-085-drift" }),
    ),
    /Failure Edge Recovery Synthetic Fixture Set upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput({ next_subphase: "RP00.P07.M06.S02" }),
    ),
    /Failure Edge Recovery Synthetic Fixture Set requires RP00\.P07\.M06\.S01 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput({ failure_edge_recovery_permission_audit_recovery_evidence_decision: "runtime_fixture_generation_started" }),
    ),
    /Failure Edge Recovery Synthetic Fixture Set requires completed CP00-085 recovery evidence boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput({ runtime_lock_acquisition_permitted: true }),
    ),
    /Failure Edge Recovery Synthetic Fixture Set requires completed CP00-085 recovery evidence boundary/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput(),
      { write_failure_fixture: true },
    ),
    /cannot claim write_failure_fixture/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput(),
      { execute_failure_unit_test: true },
    ),
    /cannot claim execute_failure_unit_test/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput(),
      { start_ldip_implementation: true },
    ),
    /cannot claim start_ldip_implementation/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput(),
      { unexpected_fixture_claim: true },
    ),
    /cannot accept unknown claim unexpected_fixture_claim/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(null),
    /recovery evidence result must be an object/,
  );
  assert.throws(
    () => assembleControlPlaneFailureEdgeRecoverySyntheticFixtureSet(
      createFailureEdgeRecoverySyntheticFixtureSetInput(),
      "bad-claims",
    ),
    /claims must be an object/,
  );
});

