test("Review Closeout Finding Routing Map fails closed on upstream drift and unsafe claims", () => {
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(null),
    /upstream permission audit binding result must be an object/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput(),
      [],
    ),
    /claims must be an object/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput({ pack_id: "CP00-092-drift" }),
    ),
    /upstream pack mismatch/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput({ next_subphase: "RP00.P09.M06.S01" }),
    ),
    /RP00.P09.M05.S11 upstream handoff/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput({ permission_audit_binding_bound: false }),
    ),
    /requires completed CP00-092 permission audit binding boundary/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput(),
      { route_unresolved_p0_as_nonblocking: true },
    ),
    /cannot claim route_unresolved_p0_as_nonblocking/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput(),
      { defer_p2_without_reason: true },
    ),
    /cannot claim defer_p2_without_reason/,
  );
  assert.throws(
    () => assembleControlPlaneReviewCloseoutFindingRoutingMap(
      createReviewCloseoutFindingRoutingMapInput(),
      { unexpected_route_claim: true },
    ),
    /cannot accept unknown claim/,
  );
});

