test("Claude review tenant boundary precheck denies actor resource and Matter tenant mismatches", () => {
  for (const [label, overrides, expectedRef] of [
    [
      "actor tenant mismatch",
      { actor_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.claude_review.tenant_boundary.actor_tenant_mismatch",
    ],
    [
      "resource tenant mismatch",
      { resource_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.claude_review.tenant_boundary.resource_tenant_mismatch",
    ],
    [
      "Matter tenant missing",
      { matter_tenant_id: null },
      "blocked.synthetic.claude_review.tenant_boundary.matter_tenant_missing",
    ],
    [
      "Matter tenant mismatch",
      { matter_tenant_id: "tenant.synthetic.other" },
      "blocked.synthetic.claude_review.tenant_boundary.matter_tenant_mismatch",
    ],
  ]) {
    const result = precheckControlPlaneClaudeReviewTenantBoundary(createNormalizedClaudeReviewRequest(overrides));
    assert.equal(result.tenant_boundary_decision, "deny_blocked_claim_required", label);
    assert.equal(result.precheck_passed, false, label);
    assert.ok(result.blocked_claim_refs.includes(expectedRef), label);
    assert.equal(result.claude_runtime_invocation_permitted, false, label);
    assert.equal(result.review_queue_write_permitted, false, label);
    assert.equal(result.service_logic_execution_permitted, false, label);
    const wrongRef = expectedRef.endsWith("actor_tenant_mismatch")
      ? "blocked.synthetic.claude_review.tenant_boundary.resource_tenant_mismatch"
      : "blocked.synthetic.claude_review.tenant_boundary.actor_tenant_mismatch";
    assert.throws(
      () => assertControlPlaneClaudeReviewTenantBoundaryPrecheckResult({
        ...result,
        blocked_claim_refs: [wrongRef],
      }),
      Error,
      `${label} requires its specific blocked claim ref`,
    );
  }
});

