test("Claude review Matter trace precheck denies Matter-required metadata without Matter", () => {
  const missingMatter = precheckControlPlaneClaudeReviewMatterTrace(
    createClaudeReviewTenantBoundaryResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
    { touches_review_packet_with_matter_data: true },
  );
  assert.equal(missingMatter.matter_trace_decision, "deny_blocked_claim_required");
  assert.equal(missingMatter.matter_trace_required, true);
  assert.equal(missingMatter.matter_trace_satisfied, false);
  assert.deepEqual(missingMatter.blocked_claim_refs, [
    "blocked.synthetic.claude_review.matter_trace.matter_required_missing",
  ]);
  assert.throws(
    () => assertControlPlaneClaudeReviewMatterTracePrecheckResult({
      ...missingMatter,
      blocked_claim_refs: ["blocked.synthetic.claude_review.matter_trace.matter_tenant_missing"],
    }),
    Error,
    "matter-required missing must carry its specific blocked ref",
  );

  const claimedMatterScoped = precheckControlPlaneClaudeReviewMatterTrace(
    createClaudeReviewTenantBoundaryResult(),
    { touches_client_facing_ai_output: true },
  );
  assert.equal(claimedMatterScoped.matter_trace_decision, "allow_metadata_only");
  assert.equal(claimedMatterScoped.matter_trace_required, true);
  assert.equal(claimedMatterScoped.matter_trace_satisfied, true);
});

test("Claude review Matter trace precheck rejects Matter tenant pair drift", () => {
  const matterTenantWithoutMatter = precheckControlPlaneClaudeReviewMatterTrace(createClaudeReviewTenantBoundaryResult({
    matter_id: null,
    matter_tenant_id: "tenant.synthetic.lawfirm",
  }));
  assert.equal(matterTenantWithoutMatter.matter_trace_decision, "deny_blocked_claim_required");
  assert.equal(matterTenantWithoutMatter.matter_trace_satisfied, false);
  assert.deepEqual(matterTenantWithoutMatter.blocked_claim_refs, [
    "blocked.synthetic.claude_review.matter_trace.matter_tenant_without_matter",
  ]);
  assert.throws(
    () => assertControlPlaneClaudeReviewMatterTracePrecheckResult({
      ...matterTenantWithoutMatter,
      blocked_claim_refs: ["blocked.synthetic.claude_review.matter_trace.matter_tenant_missing"],
    }),
    /pair-drift blocked claim ref/,
  );

  const tenantBoundaryResult = createClaudeReviewTenantBoundaryResult();
  assert.throws(
    () => precheckControlPlaneClaudeReviewMatterTrace({
      ...tenantBoundaryResult,
      matter_tenant_id: null,
    }),
    /missing Matter tenant must fail closed/,
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewMatterTrace({
      ...tenantBoundaryResult,
      matter_tenant_id: "tenant.synthetic.other",
    }),
    /Matter tenant mismatch must fail closed/,
  );
});

test("Claude review Matter trace precheck fails closed on unsafe claims and wrong source", () => {
  const tenantBoundaryResult = createClaudeReviewTenantBoundaryResult();
  for (const [label, claims] of [
    ["Matter trace bypass", { bypass_matter_trace: true }],
    ["service execution", { execute_service_logic: true }],
    ["product write", { writes_product_state: true }],
    ["runtime route", { create_runtime_route: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["audit ledger", { append_audit_ledger: true }],
    ["audit event", { write_audit_event: true }],
    ["human approval replace", { replace_human_approval: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["source completion", { complete_source_micro_phase: true }],
    ["unknown truthy claim", { unreviewed_matter_access: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewMatterTrace(tenantBoundaryResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewMatterTrace(
      { ...tenantBoundaryResult, tenant_boundary_precheck_subphase_id: "RP00.P02.M04.S02" },
    ),
    Error,
    "wrong tenant boundary marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewMatterTrace({
      ...tenantBoundaryResult,
      tenant_boundary_decision: "deny_blocked_claim_required",
      precheck_passed: false,
      blocked_claim_refs: ["blocked.synthetic.claude_review.tenant_boundary.actor_tenant_mismatch"],
    }),
    Error,
    "carried denied tenant boundary",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewMatterTrace(tenantBoundaryResult, null),
    Error,
    "non-object claims",
  );
});

