test("Claude review audit hint precheck fails closed on unsafe claims and wrong source", () => {
  const permissionResult = createClaudeReviewPermissionResult();
  for (const invalidPermissionResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewAuditHint(invalidPermissionResult),
      /requires an S05 permission result object/,
      "missing permission precheck result",
    );
  }
  for (const [label, claims] of [
    ["skip audit", { skip_audit: true }],
    ["omit audit hint", { omit_audit_hint: true }],
    ["write audit event", { write_audit_event: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["mutate audit ledger", { mutate_audit_ledger: true }],
    ["service execution", { execute_service_logic: true }],
    ["product write", { writes_product_state: true }],
    ["runtime route", { create_runtime_route: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewAuditHint(permissionResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint(permissionResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden audit claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint(permissionResult, { unreviewed_audit_override: true }),
    /unknown claim/,
    "unknown truthy audit claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      permission_precheck_subphase_id: "RP00.P02.M04.S04",
    }),
    /requires RP00.P02.M04.S05 permission result/,
    "wrong permission marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      entrypoint_id: "hermes_validation",
    }),
    /requires claude_review entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      model_id: "claude-sonnet-4-5",
    }),
    /requires claude-opus-4-8 max read-only input/,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      audit_event_ref: "",
    }),
    /requires audit_event_ref/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      permission_decision: "deny_blocked_claim_required",
    }),
    /requires carried allow_metadata_only permission pass/,
    "denied permission decision",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      permission_precheck_passed: false,
    }),
    /requires carried allow_metadata_only permission pass/,
    "failed permission precheck",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint({
      ...permissionResult,
      permission_decision_ref_satisfied: false,
    }),
    /requires satisfied permission_decision_ref/,
    "unsatisfied permission decision ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewAuditHint(permissionResult, null),
    Error,
    "non-object claims",
  );
});

