test("Claude review primary happy path allows firm-level metadata and validator rejects result drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneClaudeReviewMatterTrace(
    createClaudeReviewTenantBoundaryResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
  );
  const auditHintResult = precheckControlPlaneClaudeReviewAuditHint(
    precheckControlPlaneClaudeReviewPermission(firmLevelMatterTrace),
  );
  const result = precheckControlPlaneClaudeReviewPrimaryHappyPath(auditHintResult);
  assert.equal(assertControlPlaneClaudeReviewPrimaryHappyPathResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.happy_path_receipt.object_id, "firm_level_claude_review");
  assert.equal(result.primary_happy_path_applied, true);
  for (const [label, override] of [
    ["wrong marker", { primary_happy_path_subphase_id: "RP00.P02.M04.S06" }],
    ["runtime Claude invocation", { claude_runtime_invocation_permitted: true }],
    ["review queue write", { review_queue_write_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.claude_review.primary_happy_path"] }],
    ["wrong receipt policy", {
      happy_path_receipt: {
        ...result.happy_path_receipt,
        audit_hint_policy_ref: "CONTROL_PLANE_CLAUDE_REVIEW_PERMISSION_PRECHECK_POLICY",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneClaudeReviewAuditHint" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M04.S07" }],
  ]) {
    assert.throws(
      () => assertControlPlaneClaudeReviewPrimaryHappyPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Claude review primary happy path fails closed on unsafe claims and wrong source", () => {
  const auditHintResult = createClaudeReviewAuditHintResult();
  for (const invalidAuditHintResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewPrimaryHappyPath(invalidAuditHintResult),
      /requires S06 audit hint precheck result/,
      "missing audit hint precheck result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewPrimaryHappyPath(auditHintResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath(auditHintResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden happy path claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath(auditHintResult, { unreviewed_happy_path_override: true }),
    /unknown claim/,
    "unknown truthy happy path claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      audit_hint_precheck_subphase_id: "RP00.P02.M04.S05",
    }),
    /requires RP00.P02.M04.S06 audit hint result/,
    "wrong audit hint marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      entrypoint_id: "hermes_validation",
    }),
    /requires claude_review entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      model_id: "claude-sonnet-4-5",
    }),
    /requires claude-opus-4-8 max read-only input/,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      audit_hint: null,
    }),
    /requires S06 audit hint precheck result/,
    "missing audit hint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      audit_event_ref: "",
    }),
    /requires S06 audit hint precheck result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      audit_hint_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied audit hint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath({
      ...auditHintResult,
      audit_event_ref_satisfied: false,
    }),
    Error,
    "unsatisfied audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPrimaryHappyPath(auditHintResult, null),
    Error,
    "non-object claims",
  );
});

