test("Claude review secondary workflow path allows firm-level metadata and validator rejects result drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneClaudeReviewMatterTrace(
    createClaudeReviewTenantBoundaryResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
  );
  const primaryHappyPathResult = precheckControlPlaneClaudeReviewPrimaryHappyPath(
    precheckControlPlaneClaudeReviewAuditHint(precheckControlPlaneClaudeReviewPermission(firmLevelMatterTrace)),
  );
  const result = precheckControlPlaneClaudeReviewSecondaryWorkflowPath(primaryHappyPathResult);
  assert.equal(assertControlPlaneClaudeReviewSecondaryWorkflowPathResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.secondary_workflow_receipt.object_id, "firm_level_claude_review");
  assert.equal(result.secondary_workflow_path_applied, true);
  for (const [label, override] of [
    ["wrong marker", { secondary_workflow_path_subphase_id: "RP00.P02.M04.S07" }],
    ["runtime Claude invocation", { claude_runtime_invocation_permitted: true }],
    ["review queue write", { review_queue_write_permitted: true }],
    ["audit ledger append", { audit_ledger_append_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.claude_review.secondary_workflow_path"] }],
    ["wrong receipt behavior", {
      secondary_workflow_receipt: {
        ...result.secondary_workflow_receipt,
        primary_happy_path_behavior_ref: "precheckControlPlaneClaudeReviewAuditHint",
      },
    }],
    ["wrong behavior ref", { working_product_behavior_ref: "precheckControlPlaneClaudeReviewPrimaryHappyPath" }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M04.S08" }],
  ]) {
    assert.throws(
      () => assertControlPlaneClaudeReviewSecondaryWorkflowPathResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Claude review secondary workflow path fails closed on unsafe claims and wrong source", () => {
  const primaryHappyPathResult = createClaudeReviewPrimaryHappyPathResult();
  for (const invalidPrimaryHappyPathResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath(invalidPrimaryHappyPathResult),
      /requires S07 primary happy path result/,
      "missing primary happy path result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath(primaryHappyPathResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath(primaryHappyPathResult, { append_audit_ledger: 0 }),
    /append_audit_ledger/,
    "falsy non-false forbidden secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath(primaryHappyPathResult, { unreviewed_secondary_workflow_override: true }),
    /unknown claim/,
    "unknown truthy secondary workflow claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_subphase_id: "RP00.P02.M04.S06",
    }),
    /requires RP00.P02.M04.S07 primary happy path result/,
    "wrong primary marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      entrypoint_id: "hermes_validation",
    }),
    /requires claude_review entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      model_id: "claude-sonnet-4-5",
    }),
    /requires claude-opus-4-8 max read-only input/,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      read_only_review_required: false,
    }),
    /requires claude-opus-4-8 max read-only input/,
    "non-read-only review",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      happy_path_receipt: null,
    }),
    /requires S07 primary happy path result/,
    "missing primary receipt",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      audit_event_ref: "",
    }),
    /requires S07 primary happy path result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied primary happy path",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath({
      ...primaryHappyPathResult,
      primary_happy_path_applied: false,
    }),
    Error,
    "unapplied primary happy path",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewSecondaryWorkflowPath(primaryHappyPathResult, null),
    Error,
    "non-object claims",
  );
});

