test("Claude review lock acquisition rule allows firm-level metadata and validator rejects drift", () => {
  const firmLevelMatterTrace = precheckControlPlaneClaudeReviewMatterTrace(
    createClaudeReviewTenantBoundaryResult({
      matter_id: null,
      matter_tenant_id: null,
    }),
  );
  const idempotencyResult = precheckControlPlaneClaudeReviewIdempotencyKeyHandling(
    precheckControlPlaneClaudeReviewStateTransitionEnforcement(
      precheckControlPlaneClaudeReviewSecondaryWorkflowPath(
        precheckControlPlaneClaudeReviewPrimaryHappyPath(
          precheckControlPlaneClaudeReviewAuditHint(precheckControlPlaneClaudeReviewPermission(firmLevelMatterTrace)),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneClaudeReviewLockAcquisitionRule(idempotencyResult);
  assert.equal(assertControlPlaneClaudeReviewLockAcquisitionRuleResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.lock_receipt.object_id, "firm_level_claude_review");
  assert.equal(result.lock_acquisition_rule_applied, true);
  for (const [label, override] of [
    ["not applied", { lock_acquisition_rule_applied: false }],
    ["wrong marker", { lock_acquisition_rule_subphase_id: "RP00.P02.M04.S10" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["runtime Claude invocation", { claude_runtime_invocation_permitted: true }],
    ["review queue write", { review_queue_write_permitted: true }],
    ["idempotency write", { idempotency_record_write_permitted: true }],
    ["lock record write", { lock_record_write_permitted: true }],
    ["lock acquired", { lock_acquisition_permitted: true }],
    ["UI created", { ui_created: true }],
    ["source completed", { source_micro_phase_completed: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.lock"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M04.S11" }],
  ]) {
    assert.throws(
      () => assertControlPlaneClaudeReviewLockAcquisitionRuleResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Claude review lock acquisition rule fails closed on unsafe claims and wrong source", () => {
  const idempotencyResult = createClaudeReviewIdempotencyKeyHandlingResult();
  for (const invalidIdempotencyResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewLockAcquisitionRule(invalidIdempotencyResult),
      /requires S10 idempotency key handling result/,
      "missing idempotency key handling result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["runtime permission evaluation", { evaluate_runtime_permission: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["authz evaluator call", { call_authz_evaluator: true }],
    ["persist idempotency record", { persist_idempotency_record: true }],
    ["write idempotency store", { write_idempotency_store: true }],
    ["acquire lock", { acquire_lock: true }],
    ["acquire runtime lock", { acquire_runtime_lock: true }],
    ["lock resource", { lock_resource: true }],
    ["lock matter", { lock_matter: true }],
    ["persist lock record", { persist_lock_record: true }],
    ["write lock store", { write_lock_store: true }],
    ["create UI", { create_ui: true }],
    ["render UI", { render_ui: true }],
    ["permission audit bypass", { bypass_permission_audit: true }],
    ["audit hint bypass", { bypass_audit_hint: true }],
    ["primary happy path bypass", { bypass_primary_happy_path: true }],
    ["secondary workflow bypass", { bypass_secondary_workflow_path: true }],
    ["state transition bypass", { bypass_state_transition: true }],
    ["idempotency bypass", { bypass_idempotency_key: true }],
    ["lock rule bypass", { bypass_lock_acquisition_rule: true }],
    ["human approval bypass", { bypass_human_approval: true }],
    ["Hermes bypass", { bypass_hermes_gate: true }],
    ["Claude review bypass", { bypass_claude_review: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewLockAcquisitionRule(idempotencyResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule(idempotencyResult, { persist_lock_record: 0 }),
    /persist_lock_record/,
    "falsy non-false forbidden lock claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule(idempotencyResult, { unreviewed_lock_override: true }),
    /unknown claim/,
    "unknown truthy lock claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_key_handling_subphase_id: "RP00.P02.M04.S09",
    }),
    /requires RP00.P02.M04.S10 idempotency key handling result/,
    "wrong idempotency marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      entrypoint_id: "hermes_validation",
    }),
    /requires claude_review entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      model_id: "claude-sonnet-4-5",
    }),
    /requires claude-opus-4-8 max read-only input/,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_receipt: null,
    }),
    /requires S10 idempotency key handling result/,
    "missing idempotency receipt",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      audit_event_ref: "",
    }),
    /requires S10 idempotency key handling result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule({
      ...idempotencyResult,
      idempotency_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied idempotency result",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewLockAcquisitionRule(idempotencyResult, null),
    Error,
    "non-object claims",
  );
});

