test("Claude review persistence boundary allows firm-level metadata and validator rejects drift", () => {
  const firmLevelLockRule = precheckControlPlaneClaudeReviewLockAcquisitionRule(
    precheckControlPlaneClaudeReviewIdempotencyKeyHandling(
      precheckControlPlaneClaudeReviewStateTransitionEnforcement(
        precheckControlPlaneClaudeReviewSecondaryWorkflowPath(
          precheckControlPlaneClaudeReviewPrimaryHappyPath(
            precheckControlPlaneClaudeReviewAuditHint(
              precheckControlPlaneClaudeReviewPermission(
                precheckControlPlaneClaudeReviewMatterTrace(
                  createClaudeReviewTenantBoundaryResult({
                    matter_id: null,
                    matter_tenant_id: null,
                  }),
                ),
              ),
            ),
          ),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneClaudeReviewPersistenceBoundary(firmLevelLockRule);
  assert.equal(assertControlPlaneClaudeReviewPersistenceBoundaryResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.persistence_receipt.object_id, "firm_level_claude_review");
  for (const [label, override] of [
    ["not applied", { persistence_boundary_applied: false }],
    ["wrong marker", { persistence_boundary_subphase_id: "RP00.P02.M04.S11" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product persistence", { product_state_persistence_permitted: true }],
    ["persistence record write", { persistence_record_write_permitted: true }],
    ["runtime Claude invocation", { claude_runtime_invocation_permitted: true }],
    ["review queue write", { review_queue_write_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.claude_review.persistence"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M04.S12" }],
  ]) {
    assert.throws(
      () => assertControlPlaneClaudeReviewPersistenceBoundaryResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Claude review persistence boundary fails closed on unsafe claims and wrong source", () => {
  const lockRuleResult = createClaudeReviewLockAcquisitionRuleResult();
  for (const invalidLockRuleResult of [null, undefined, []]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewPersistenceBoundary(invalidLockRuleResult),
      /requires S11 lock acquisition rule result/,
      "missing lock acquisition rule result",
    );
  }
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["object store write", { write_object_store: true }],
    ["runtime Claude invocation", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["runtime lock", { acquire_runtime_lock: true }],
    ["runtime permission engine", { run_permission_engine: true }],
    ["persistence boundary bypass", { bypass_persistence_boundary: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source completion", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewPersistenceBoundary(lockRuleResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary(lockRuleResult, { write_database: 0 }),
    /write_database/,
    "falsy non-false forbidden persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary(lockRuleResult, { unreviewed_persistence_override: true }),
    /unknown claim/,
    "unknown truthy persistence claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_rule_subphase_id: "RP00.P02.M04.S10",
    }),
    /requires RP00.P02.M04.S11 lock acquisition rule result/,
    "wrong lock marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      entrypoint_id: "hermes_validation",
    }),
    /requires claude_review entrypoint/,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      model_id: "claude-sonnet-4-5",
    }),
    /requires claude-opus-4-8 max read-only input/,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      lock_receipt: null,
    }),
    /requires S11 lock acquisition rule result/,
    "missing lock receipt",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      audit_event_ref: "",
    }),
    /requires S11 lock acquisition rule result/,
    "missing audit event ref",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary({
      ...lockRuleResult,
      lock_acquisition_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied lock result",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewPersistenceBoundary(lockRuleResult, null),
    Error,
    "non-object claims",
  );
});

