test("Claude review error mapping allows firm-level metadata and validator rejects drift", () => {
  const firmLevelPersistence = precheckControlPlaneClaudeReviewPersistenceBoundary(
    precheckControlPlaneClaudeReviewLockAcquisitionRule(
      precheckControlPlaneClaudeReviewIdempotencyKeyHandling(
        precheckControlPlaneClaudeReviewStateTransitionEnforcement(
          precheckControlPlaneClaudeReviewSecondaryWorkflowPath(
            precheckControlPlaneClaudeReviewPrimaryHappyPath(
              precheckControlPlaneClaudeReviewAuditHint(
                precheckControlPlaneClaudeReviewPermission(
                  precheckControlPlaneClaudeReviewMatterTrace(
                    createClaudeReviewTenantBoundaryResult({
                      matter_id: null,
                      matter_tenant_id: null,
                    }),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    ),
  );
  const result = precheckControlPlaneClaudeReviewErrorMapping(firmLevelPersistence);
  assert.equal(assertControlPlaneClaudeReviewErrorMappingResult(result), true);
  assert.equal(result.matter_id, null);
  assert.equal(result.matter_tenant_id, null);
  assert.equal(result.validation_error_mapping_receipt.object_id, "firm_level_claude_review");
  for (const [label, override] of [
    ["not applied", { validation_error_mapping_applied: false }],
    ["wrong marker", { validation_error_mapping_subphase_id: "RP00.P02.M04.S12" }],
    ["bad key", { idempotency_key: "idem.real.client-data" }],
    ["runtime error mapping", { runtime_error_mapping_permitted: true }],
    ["exception translation", { exception_translation_permitted: true }],
    ["error record write", { error_record_write_permitted: true }],
    ["database write", { database_write_permitted: true }],
    ["storage write", { storage_write_permitted: true }],
    ["product persistence", { product_state_persistence_permitted: true }],
    ["persistence record write", { persistence_record_write_permitted: true }],
    ["Claude runtime", { claude_runtime_invocation_permitted: true }],
    ["review queue", { review_queue_write_permitted: true }],
    ["audit event write", { audit_event_write_permitted: true }],
    ["blocked refs", { blocked_claim_refs: ["blocked.synthetic.error_mapping"] }],
    ["wrong next subphase", { next_subphase: "RP00.P02.M04.S13" }],
  ]) {
    assert.throws(
      () => assertControlPlaneClaudeReviewErrorMappingResult({ ...result, ...override }),
      Error,
      label,
    );
  }
});

test("Claude review error mapping fails closed on unsafe claims and wrong source", () => {
  const persistenceBoundaryResult = createClaudeReviewPersistenceBoundaryResult();
  for (const [label, claims] of [
    ["service execution", { execute_service_logic: true }],
    ["runtime route", { create_runtime_route: true }],
    ["product write", { writes_product_state: true }],
    ["persist product state", { persist_product_state: true }],
    ["database write", { write_database: true }],
    ["storage write", { write_storage: true }],
    ["Claude runtime", { invoke_claude_runtime_review: true }],
    ["review queue", { write_review_queue: true }],
    ["review assignment", { write_review_assignment: true }],
    ["review notification", { write_review_notification: true }],
    ["append audit ledger", { append_audit_ledger: true }],
    ["write audit event", { write_audit_event: true }],
    ["idempotency store write", { write_idempotency_store: true }],
    ["lock store write", { write_lock_store: true }],
    ["persistence store write", { write_persistence_store: true }],
    ["runtime error mapping", { map_runtime_error: true }],
    ["register error mapper", { register_error_mapper: true }],
    ["runtime exception translation", { translate_runtime_exception: true }],
    ["persist error record", { persist_error_record: true }],
    ["write error store", { write_error_store: true }],
    ["error UI", { create_error_ui: true }],
    ["validation error mapping bypass", { bypass_validation_error_mapping: true }],
    ["real client data", { use_real_client_data: true }],
    ["real matter data", { use_real_matter_data: true }],
    ["source complete", { complete_source_micro_phase: true }],
  ]) {
    assert.throws(
      () => precheckControlPlaneClaudeReviewErrorMapping(persistenceBoundaryResult, claims),
      Error,
      label,
    );
  }
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping(persistenceBoundaryResult, { map_runtime_error: 0 }),
    /map_runtime_error/,
    "falsy non-false forbidden validation error mapping claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping(persistenceBoundaryResult, { unreviewed_error_mapping_override: true }),
    /unknown claim/,
    "unknown truthy validation error mapping claim",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      persistence_boundary_subphase_id: "RP00.P02.M04.S11",
    }),
    Error,
    "wrong persistence marker",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      entrypoint_id: "hermes_validation",
    }),
    Error,
    "wrong entrypoint",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      model_id: "claude-sonnet-4-5",
    }),
    Error,
    "wrong model",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      read_only_review_required: false,
    }),
    Error,
    "non-read-only",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      persistence_receipt: null,
    }),
    Error,
    "missing persistence receipt",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping({
      ...persistenceBoundaryResult,
      persistence_decision: "deny_blocked_claim_required",
    }),
    Error,
    "denied persistence result",
  );
  assert.throws(
    () => precheckControlPlaneClaudeReviewErrorMapping(persistenceBoundaryResult, null),
    Error,
    "non-object claims",
  );
});

