  assert.equal(CONTROL_PLANE_CLAUDE_REVIEW_REQUIRED_ROUTING_PRECHECKER.doesNotWriteHumanApproval, true);
  assert.equal(CONTROL_PLANE_CLAUDE_REVIEW_REQUIRED_ROUTING_PRECHECKER.completesSourceMicroPhase, true);
