test("Claude review required routing fixture mirrors the policy", async () => {
  const fixture = JSON.parse(
    await readFile(new URL("../fixtures/synthetic-control-plane.json", import.meta.url), "utf8"),
  );
  const reviewRoutingFixture = fixture.control_plane_claude_review_required_routing;
  const runtimePrecheckResult = precheckControlPlaneClaudeReviewRequiredRouting(
    fixture.control_plane_claude_review_error_mapping.precheck_result,
  );
  assert.deepEqual(JSON.parse(JSON.stringify(runtimePrecheckResult)), reviewRoutingFixture.precheck_result);
  assert.equal(reviewRoutingFixture.subphase_id, "RP00.P02.M04.S14");
  assert.equal(reviewRoutingFixture.source_micro_phase_id, "RP00.P02.M04");
  assert.equal(
    reviewRoutingFixture.policy_ref,
    "CONTROL_PLANE_CLAUDE_REVIEW_REQUIRED_ROUTING_POLICY",
  );
  assert.deepEqual(
    reviewRoutingFixture.result_fields,
    CONTROL_PLANE_CLAUDE_REVIEW_REQUIRED_ROUTING_RESULT_FIELDS,
  );
  assert.equal(reviewRoutingFixture.precheck_result.validation_error_mapping_subphase_id, "RP00.P02.M04.S13");
  assert.equal(reviewRoutingFixture.precheck_result.review_required_routing_subphase_id, "RP00.P02.M04.S14");
  assert.equal(reviewRoutingFixture.precheck_result.review_required_decision, "review_required_metadata_only");
  assert.equal(reviewRoutingFixture.precheck_result.review_required_scope, "synthetic_control_plane_claude_review_required_routing");
  assert.equal(reviewRoutingFixture.precheck_result.review_required_receipt.working_product_behavior_ref, "precheckControlPlaneClaudeReviewRequiredRouting");
  assert.deepEqual(reviewRoutingFixture.precheck_result.blocked_claim_refs, []);
  assert.equal(reviewRoutingFixture.precheck_result.claude_runtime_invocation_permitted, false);
  assert.equal(reviewRoutingFixture.precheck_result.review_queue_write_permitted, false);
  assert.equal(reviewRoutingFixture.precheck_result.review_assignment_write_permitted, false);
  assert.equal(reviewRoutingFixture.precheck_result.review_notification_permitted, false);
  assert.equal(reviewRoutingFixture.precheck_result.human_approval_record_write_permitted, false);
  assert.equal(reviewRoutingFixture.fixture_integrity.generated_by, "precheckControlPlaneClaudeReviewRequiredRouting");
  assert.equal(reviewRoutingFixture.fixture_integrity.consumed_validation_error_mapping_ref, "RP00.P02.M04.S13");
  assert.equal(reviewRoutingFixture.completes_source_micro_phase, true);
  assert.equal(reviewRoutingFixture.no_real_data, true);
  assert.equal(reviewRoutingFixture.writes_product_state, false);
  assert.equal(reviewRoutingFixture.next_subphase, "RP00.P02.M05.S01");
});
